function getBaseUrl() {
  if (process.env.NEXT_PUBLIC_BASE_URL) return process.env.NEXT_PUBLIC_BASE_URL;
  if (process.env.VERCEL_URL) return `https://${process.env.VERCEL_URL}`;
  return "http://localhost:3000";
}

export async function GET(req: Request) {
  const url = new URL(req.url);
  const debug = url.searchParams.get("debug") === "1";

  const t0 = Date.now();

  // Warm techfeed SKU lookup cache
  const tf0 = Date.now();
  const tf = await warmTechfeedWheelCache();
  const techfeedMs = Date.now() - tf0;

  // Warm the new fast browse cache (builds style index)
  const browse0 = Date.now();
  const browse = await warmBrowseCache();
  const browseMs = Date.now() - browse0;

  // Warm the WheelPros wheels search path (wrapper + our in-memory cache).
  const base = getBaseUrl();
  const wp0 = Date.now();
  const wheelsUrl = `${base}/api/wheelpros/wheels/search?page=1&pageSize=8&fields=images&priceType=msrp&currencyCode=USD&boltPattern=5x115${debug ? "&debug=1" : ""}`;
  let wheelsStatus = 0;
  try {
    const res = await fetch(wheelsUrl, { cache: "no-store" });
    wheelsStatus = res.status;
    // Drain body to avoid leaking sockets
    await res.arrayBuffer();
  } catch {
    wheelsStatus = 0;
  }
  const wheelsMs = Date.now() - wp0;

  const totalMs = Date.now() - t0;

  return NextResponse.json(
    {
      ok: true,
      techfeed: { ...tf, ms: techfeedMs },
      browse: { ...browse, ms: browseMs },
      wheelpros: { url: wheelsUrl, status: wheelsStatus, ms: wheelsMs },
      totalMs,
      at: new Date().toISOString(),
    },
    {
      headers: {
        "cache-control": "no-store",
        ...(debug
          ? {
              "x-wt-techfeed-ms": String(techfeedMs),
              "x-wt-browse-ms": String(browseMs),
              "x-wt-wheelpros-ms": String(wheelsMs),
              "x-wt-total-ms": String(totalMs),
              "server-timing": `techfeed;dur=${techfeedMs}, browse;dur=${browseMs}, wheelpros;dur=${wheelsMs}, total;dur=${totalMs}`,
            }
          : null),
      },
    }
  );
}

/**
 * Wheel Pros Product API client
 * Docs: https://developer.wheelpros.com/assets/specs/product-api/openapi/api.html
 */

import { getWheelProsToken } from "@/lib/wheelprosAuth";

function baseUrl() {
  const base = process.env.WHEELPROS_PRODUCT_API_BASE_URL || "https://api.wheelpros.com/product/v1";
  // Ensure trailing slash so relative URLs resolve correctly
  return base.endsWith("/") ? base : base + "/";
}

export type WheelSearchParams = {
  // Vehicle fitment
  vehicleYear?: number;
  vehicleMake?: string;
  vehicleModel?: string;
  vehicleSubModel?: string;
  
  // Specs
  boltPattern?: string;
  diameter?: number;
  width?: string;
  minOffset?: number;
  maxOffset?: number;
  centerbore?: string;
  
  // Filters
  brand?: string;
  finish?: string;
  
  // Options
  includeLifted?: boolean;
  includeStaggered?: boolean;
  availabilityType?: "ALL" | "LOCAL" | "AVAILABLE";
  
  // Pagination
  page?: number;
  pageSize?: number;
  
  // Sorting
  sortField?: "brand" | "popularity" | "price" | "status" | "style" | "styleNumber";
  sortOrder?: "asc" | "desc";
  
  // Extra fields
  fields?: string; // e.g., "inventory,price"
};

export type WheelSearchResult = {
  content: Array<{
    sku?: string;
    styleNumber?: string;
    styleName?: string;
    brand?: string;
    brandCode?: string;
    finish?: string;
    diameter?: number;
    width?: number;
    offset?: number;
    boltPattern?: string;
    centerbore?: number;
    msrp?: number;
    mapPrice?: number;
    images?: Array<{ url?: string; type?: string }>;
    inventory?: Array<{ warehouse?: string; quantity?: number }>;
  }>;
  pageable?: {
    pageNumber?: number;
    pageSize?: number;
  };
  totalElements?: number;
  totalPages?: number;
  facets?: {
    brands?: Array<{ key: string; count: number }>;
    finishes?: Array<{ key: string; count: number }>;
    diameters?: Array<{ key: number; count: number }>;
    widths?: Array<{ key: number; count: number }>;
    boltPatterns?: Array<{ key: string; count: number }>;
  };
};

export async function searchWheels(params: WheelSearchParams): Promise<WheelSearchResult> {
  const token = await getWheelProsToken();
  const url = new URL("wheel/search", baseUrl());
  
  // Add query params
  if (params.vehicleYear) url.searchParams.set("vehicleYear", String(params.vehicleYear));
  if (params.vehicleMake) url.searchParams.set("vehicleMake", params.vehicleMake);
  if (params.vehicleModel) url.searchParams.set("vehicleModel", params.vehicleModel);
  if (params.vehicleSubModel) url.searchParams.set("vehicleSubModel", params.vehicleSubModel);
  
  if (params.boltPattern) url.searchParams.set("boltPattern", params.boltPattern);
  if (params.diameter) url.searchParams.set("diameter", String(params.diameter));
  if (params.width) url.searchParams.set("width", params.width);
  if (params.minOffset !== undefined) url.searchParams.set("minOffset", String(params.minOffset));
  if (params.maxOffset !== undefined) url.searchParams.set("maxOffset", String(params.maxOffset));
  if (params.centerbore) url.searchParams.set("centerbore", params.centerbore);
  
  if (params.brand) url.searchParams.set("brand", params.brand);
  if (params.finish) url.searchParams.set("finish", params.finish);
  
  if (params.includeLifted) url.searchParams.set("includeLifted", "true");
  if (params.includeStaggered) url.searchParams.set("includeStaggered", "true");
  if (params.availabilityType) url.searchParams.set("availabilityType", params.availabilityType);
  
  url.searchParams.set("page", String(params.page || 1));
  url.searchParams.set("pageSize", String(params.pageSize || 50));
  
  if (params.sortField) url.searchParams.set("sortField", params.sortField);
  if (params.sortOrder) url.searchParams.set("sortOrder", params.sortOrder);
  
  // Always request price info
  url.searchParams.set("fields", params.fields || "price");
  url.searchParams.set("facetCount", "50"); // Get more facet buckets
  
  const res = await fetch(url.toString(), {
    headers: {
      Accept: "application/json",
      Authorization: `Bearer ${token}`,
    },
    cache: "no-store",
  });
  
  if (!res.ok) {
    let detail = "";
    try {
      detail = (await res.text()).slice(0, 500);
    } catch {}
    throw new Error(`WheelPros wheel search failed: HTTP ${res.status}${detail ? ` :: ${detail}` : ""}`);
  }
  
  return (await res.json()) as WheelSearchResult;
}

import fs from "node:fs/promises";
import path from "node:path";
import zlib from "node:zlib";

export type TechfeedWheel = {
  sku: string;
  product_desc?: string;
  brand_cd?: string;
  brand_desc?: string;
  style?: string;
  display_style_no?: string;

  diameter?: string;
  width?: string;
  offset?: string;
  centerbore?: string;
  backspacing?: string;

  lug_count?: string;
  bolt_pattern_metric?: string;
  bolt_pattern_standard?: string;

  abbreviated_finish_desc?: string;
  fancy_finish_desc?: string;
  box_label_desc?: string;

  msrp?: string;
  map_price?: string;

  images?: string[];
};

type WheelsBySkuFile = {
  generatedAt?: string;
  rows?: number;
  bySku: Record<string, TechfeedWheel>;
};

type WheelsByStyleFile = {
  generatedAt?: string;
  rows?: number;
  byStyle: Record<string, TechfeedWheel[]>;
};

let bySkuCache: WheelsBySkuFile | null = null;
let byStyleCache: WheelsByStyleFile | null = null;

// Bolt-pattern index (built lazily, per server instance)
let byBoltPatternCache: Map<string, TechfeedWheel[]> | null = null;
let techfeedIndexBuiltAt: string | null = null;

async function loadGzJson<T>(relPath: string): Promise<T | null> {
  try {
    const abs = path.join(process.cwd(), relPath);
    const buf = await fs.readFile(abs);
    const json = zlib.gunzipSync(buf).toString("utf8");
    return JSON.parse(json) as T;
  } catch {
    return null;
  }
}

export async function getTechfeedWheelBySku(sku: string): Promise<TechfeedWheel | null> {
  if (!sku) return null;
  if (!bySkuCache) {
    bySkuCache = await loadGzJson<WheelsBySkuFile>("src/techfeed/wheels_by_sku.json.gz");
  }
  if (!bySkuCache?.bySku) return null;
  return bySkuCache.bySku[sku] || null;
}

/**
 * Best-effort warmup so first real user request after deploy doesn't pay the gunzip+parse cost.
 * Returns a sample SKU when available.
 */
export async function warmTechfeedWheelCache(): Promise<{ loaded: boolean; firstSku?: string }> {
  if (!bySkuCache) {
    bySkuCache = await loadGzJson<WheelsBySkuFile>("src/techfeed/wheels_by_sku.json.gz");
  }
  const keys = bySkuCache?.bySku ? Object.keys(bySkuCache.bySku) : [];
  return { loaded: Boolean(keys.length), firstSku: keys[0] };
}

export async function getTechfeedWheelsByStyle(style: string): Promise<TechfeedWheel[] | null> {
  if (!style) return null;
  if (!byStyleCache) {
    byStyleCache = await loadGzJson<WheelsByStyleFile>("src/techfeed/wheels_by_style.json.gz");
  }
  if (!byStyleCache?.byStyle) return null;
  return byStyleCache.byStyle[style] || null;
}

function normalizeBoltPatternKey(bp: string): string {
  return String(bp || "")
    .toLowerCase()
    .replace(/\s/g, "")
    .replace(/[×-]/g, "x")
    .trim();
}

function parseBoltPatternKeys(bp: string): string[] {
  const raw = String(bp || "").trim();
  if (!raw) return [];
  const parts = raw.split(/[\/,]/).map((p) => normalizeBoltPatternKey(p));
  return parts.filter(Boolean);
}

/**
 * Build / cache a bolt-pattern index for quick candidate lookup.
 * NOTE: This is best-effort and lives in-memory per server instance.
 */
async function ensureBoltPatternIndex(): Promise<void> {
  if (byBoltPatternCache) return;
  if (!bySkuCache) {
    bySkuCache = await loadGzJson<WheelsBySkuFile>("src/techfeed/wheels_by_sku.json.gz");
  }

  const idx = new Map<string, TechfeedWheel[]>();
  const bySku = bySkuCache?.bySku || {};
  for (const w of Object.values(bySku)) {
    const bpRaw = w.bolt_pattern_metric || w.bolt_pattern_standard || "";
    const keys = parseBoltPatternKeys(bpRaw);
    if (!keys.length) continue;
    for (const k of keys) {
      const arr = idx.get(k);
      if (arr) arr.push(w);
      else idx.set(k, [w]);
    }
  }

  byBoltPatternCache = idx;
  techfeedIndexBuiltAt = new Date().toISOString();
}

export async function getTechfeedCandidatesByBoltPattern(boltPattern: string): Promise<TechfeedWheel[]> {
  await ensureBoltPatternIndex();
  const k = normalizeBoltPatternKey(boltPattern);
  return (byBoltPatternCache?.get(k) || []).slice();
}

export function getTechfeedIndexBuiltAt(): string | null {
  return techfeedIndexBuiltAt;
}

