  generatedAt?: string;
  rows?: number;
  bySku: Record<string, TechfeedWheel>;
};

let dataCache: WheelsBySkuFile | null = null;
let stylesCache: Map<string, WheelStyle> | null = null;
let stylesList: WheelStyle[] | null = null;

async function loadData(): Promise<WheelsBySkuFile | null> {
  if (dataCache) return dataCache;
  try {
    const abs = path.join(process.cwd(), "src/techfeed/wheels_by_sku.json.gz");
    const buf = await fs.readFile(abs);
    const json = zlib.gunzipSync(buf).toString("utf8");
    dataCache = JSON.parse(json) as WheelsBySkuFile;
    return dataCache;
  } catch (e) {
    console.error("[wheels-browse] Failed to load techfeed:", e);
    return null;
  }
}

function buildStylesIndex(data: WheelsBySkuFile): Map<string, WheelStyle> {
  if (stylesCache) return stylesCache;

  const styles = new Map<string, WheelStyle>();

  for (const [sku, w] of Object.entries(data.bySku)) {
    const styleKey = w.style || w.display_style_no || "";
    if (!styleKey) continue;

    const boltPattern = w.bolt_pattern_metric || w.bolt_pattern_standard || "";
    const diameter = w.diameter || "";
    const width = w.width || "";
    const offset = w.offset || "";
    const centerbore = w.centerbore || "";
    const finish = w.abbreviated_finish_desc || w.fancy_finish_desc || "";
    const price = w.msrp ? parseFloat(w.msrp) : undefined;
    const imageUrl = w.images?.[0];

    let style = styles.get(styleKey);
    if (!style) {
      style = {
        styleKey,
        brand: w.brand_desc || "",
        brandCode: w.brand_cd || "",
        model: w.product_desc || styleKey,
        imageUrl,
        price,
        finishes: [],
        skus: [],
      };
      styles.set(styleKey, style);
    }

    // Update representative image/price if this one has them
    if (!style.imageUrl && imageUrl) style.imageUrl = imageUrl;
    if (style.price === undefined && price) style.price = price;
    if (price && style.price && price < style.price) style.price = price;

    // Add to skus list
    style.skus.push({
      sku,
      diameter,
      width,
      offset,
      boltPattern,
      centerbore,
      finish,
      price,
    });

    // Track unique finishes
    if (finish && !style.finishes.some(f => f.finish === finish)) {
      style.finishes.push({
        finish,
        sku,
        imageUrl,
        price,
        diameter,
        width,
        offset,
      });
    }
  }

  stylesCache = styles;
  return styles;
}

export type BrowseFilters = {
  boltPattern?: string;
  diameter?: string;
  width?: string;
  offsetMin?: number;
  offsetMax?: number;
  centerbore?: string;
  brandCode?: string;
  finish?: string;
  priceMin?: number;
  priceMax?: number;
};

export type BrowseResult = {
  styles: WheelStyle[];
  totalStyles: number;
  facets: {
    brands: Array<{ code: string; name: string; count: number }>;
    finishes: Array<{ value: string; count: number }>;
    diameters: Array<{ value: string; count: number }>;
    widths: Array<{ value: string; count: number }>;
    boltPatterns: Array<{ value: string; count: number }>;
  };
  cacheHit: boolean;
  loadMs: number;
  filterMs: number;
};

export async function browseWheels(
  filters: BrowseFilters,
  page: number = 1,
  pageSize: number = 24
): Promise<BrowseResult> {
  const t0 = Date.now();

  const data = await loadData();
  if (!data?.bySku) {
    return {
      styles: [],
      totalStyles: 0,
      facets: { brands: [], finishes: [], diameters: [], widths: [], boltPatterns: [] },
      cacheHit: false,
      loadMs: Date.now() - t0,
      filterMs: 0,
    };
  }

  const loadMs = Date.now() - t0;
  const t1 = Date.now();
  const cacheHit = stylesCache !== null;

  const stylesMap = buildStylesIndex(data);

  // Build list if not cached
  if (!stylesList) {
    stylesList = Array.from(stylesMap.values());
  }

  // Filter styles based on criteria
  let filtered = stylesList;

  if (filters.boltPattern) {
    const bp = filters.boltPattern.toUpperCase().replace(/\s/g, "");
    filtered = filtered.filter(s => 
      s.skus.some(sku => {
        const skuBp = sku.boltPattern.toUpperCase().replace(/\s/g, "");
        return skuBp === bp || skuBp.includes(bp);
      })
    );
  }

  if (filters.diameter) {
    const d = parseFloat(filters.diameter);
    filtered = filtered.filter(s =>
      s.skus.some(sku => {
        const skuD = parseFloat(sku.diameter);
        return Math.abs(skuD - d) < 0.1;
      })
    );
  }

  if (filters.width) {
    const w = parseFloat(filters.width);
    filtered = filtered.filter(s =>
      s.skus.some(sku => {
        const skuW = parseFloat(sku.width);
        return Math.abs(skuW - w) < 0.1;
      })
    );
  }

  if (filters.offsetMin !== undefined || filters.offsetMax !== undefined) {
    filtered = filtered.filter(s =>
      s.skus.some(sku => {
        const o = parseFloat(sku.offset);
        if (!Number.isFinite(o)) return false;
        if (filters.offsetMin !== undefined && o < filters.offsetMin) return false;
        if (filters.offsetMax !== undefined && o > filters.offsetMax) return false;
        return true;
      })
    );
  }

  if (filters.centerbore) {
    const cb = parseFloat(filters.centerbore);
    filtered = filtered.filter(s =>
      s.skus.some(sku => {
        const skuCb = parseFloat(sku.centerbore);
        // Wheel centerbore must be >= vehicle hub (with small tolerance)
        return skuCb >= cb - 0.5;
      })
    );
  }

  if (filters.brandCode) {
    filtered = filtered.filter(s => s.brandCode === filters.brandCode);
  }

  if (filters.finish) {
    const f = filters.finish.toLowerCase();
    filtered = filtered.filter(s =>
      s.finishes.some(fin => fin.finish.toLowerCase().includes(f))
    );
  }

  if (filters.priceMin !== undefined || filters.priceMax !== undefined) {
    filtered = filtered.filter(s => {
      const p = s.price;
      if (p === undefined) return false;
      if (filters.priceMin !== undefined && p < filters.priceMin) return false;
      if (filters.priceMax !== undefined && p > filters.priceMax) return false;
      return true;
    });
  }

  // Prefer styles with images
  const withImages = filtered.filter(s => s.imageUrl);
  const finalFiltered = withImages.length >= Math.min(12, filtered.length) ? withImages : filtered;

  // Sort by price (low to high)
  finalFiltered.sort((a, b) => {
    const pa = a.price ?? Infinity;
    const pb = b.price ?? Infinity;
    return pa - pb;
  });

  // Helper to check if a SKU matches the current filters
  function skuMatchesFilters(sku: WheelStyle["skus"][0]): boolean {
    if (filters.boltPattern) {
      const bp = filters.boltPattern.toUpperCase().replace(/\s/g, "");
      const skuBp = sku.boltPattern.toUpperCase().replace(/\s/g, "");
      if (!(skuBp === bp || skuBp.includes(bp))) return false;
    }
    if (filters.diameter) {
      const d = parseFloat(filters.diameter);
      const skuD = parseFloat(sku.diameter);
      if (Math.abs(skuD - d) >= 0.1) return false;
    }
    if (filters.width) {
      const w = parseFloat(filters.width);
      const skuW = parseFloat(sku.width);
      if (Math.abs(skuW - w) >= 0.1) return false;
    }
    if (filters.offsetMin !== undefined || filters.offsetMax !== undefined) {
      const o = parseFloat(sku.offset);
      if (!Number.isFinite(o)) return false;
      if (filters.offsetMin !== undefined && o < filters.offsetMin) return false;
      if (filters.offsetMax !== undefined && o > filters.offsetMax) return false;
    }
    if (filters.centerbore) {
      const cb = parseFloat(filters.centerbore);
      const skuCb = parseFloat(sku.centerbore);
      if (skuCb < cb - 0.5) return false;
    }
    return true;
  }

  // Build facets from filtered results, only counting SKUs that match filters
  const brandCounts = new Map<string, { name: string; count: number }>();
  const finishCounts = new Map<string, number>();
  const diameterCounts = new Map<string, number>();
  const widthCounts = new Map<string, number>();
  const boltPatternCounts = new Map<string, number>();

  for (const s of finalFiltered) {
    // Brand
    if (s.brandCode) {
      const existing = brandCounts.get(s.brandCode);
      if (existing) {
        existing.count++;
      } else {
        brandCounts.set(s.brandCode, { name: s.brand, count: 1 });
      }
    }

    // Only count SKUs that actually match the filters for size/bolt facets
    const matchingSkus = s.skus.filter(skuMatchesFilters);

    // Finishes (only from matching SKUs)
    const seenFinish = new Set<string>();
    for (const sku of matchingSkus) {
      if (sku.finish && !seenFinish.has(sku.finish)) {
        seenFinish.add(sku.finish);
        finishCounts.set(sku.finish, (finishCounts.get(sku.finish) || 0) + 1);
      }
    }

    // Diameters/widths/bolt patterns from matching SKUs only
    const seenD = new Set<string>();
    const seenW = new Set<string>();
    const seenBp = new Set<string>();
    for (const sku of matchingSkus) {
      if (sku.diameter && !seenD.has(sku.diameter)) {
        seenD.add(sku.diameter);
        diameterCounts.set(sku.diameter, (diameterCounts.get(sku.diameter) || 0) + 1);
      }
      if (sku.width && !seenW.has(sku.width)) {
        seenW.add(sku.width);
        widthCounts.set(sku.width, (widthCounts.get(sku.width) || 0) + 1);
      }
      if (sku.boltPattern && !seenBp.has(sku.boltPattern)) {
        seenBp.add(sku.boltPattern);
        boltPatternCounts.set(sku.boltPattern, (boltPatternCounts.get(sku.boltPattern) || 0) + 1);
      }
    }
  }

  // Paginate
  const start = (page - 1) * pageSize;
  const pageStylesRaw = finalFiltered.slice(start, start + pageSize);

  // Filter SKUs and finishes in returned styles to only show matching ones
  const pageStyles = pageStylesRaw.map(s => {
    const matchingSkus = s.skus.filter(skuMatchesFilters);
    const matchingFinishes = s.finishes.filter(f => 
      matchingSkus.some(sku => sku.finish === f.finish)
    );
    // Update price to lowest matching SKU
    const lowestPrice = matchingSkus.reduce((min, sku) => {
      if (sku.price !== undefined && (min === undefined || sku.price < min)) return sku.price;
      return min;
    }, undefined as number | undefined);
    // Pick image from matching finish/sku if available
    const matchingImage = matchingFinishes[0]?.imageUrl || matchingSkus[0]?.sku ? s.imageUrl : s.imageUrl;

    return {
      ...s,
      skus: matchingSkus,
      finishes: matchingFinishes.length > 0 ? matchingFinishes : s.finishes.slice(0, 1),
      price: lowestPrice ?? s.price,
      imageUrl: matchingImage,
    };
  });

  const filterMs = Date.now() - t1;

  return {
    styles: pageStyles,
    totalStyles: finalFiltered.length,
    facets: {
      brands: Array.from(brandCounts.entries())
        .map(([code, { name, count }]) => ({ code, name, count }))
        .sort((a, b) => b.count - a.count)
        .slice(0, 30),
      finishes: Array.from(finishCounts.entries())
        .map(([value, count]) => ({ value, count }))
        .sort((a, b) => b.count - a.count)
        .slice(0, 30),
      diameters: Array.from(diameterCounts.entries())
        .map(([value, count]) => ({ value, count }))
        .sort((a, b) => parseFloat(a.value) - parseFloat(b.value))
        .slice(0, 20),
      widths: Array.from(widthCounts.entries())
        .map(([value, count]) => ({ value, count }))
        .sort((a, b) => parseFloat(a.value) - parseFloat(b.value))
        .slice(0, 20),
      boltPatterns: Array.from(boltPatternCounts.entries())
        .map(([value, count]) => ({ value, count }))
        .sort((a, b) => b.count - a.count)
        .slice(0, 30),
    },
    cacheHit,
    loadMs,
    filterMs,
  };
}

/**
 * Warmup: load and index data so first user request is fast
 */
export async function warmBrowseCache(): Promise<{ loaded: boolean; styleCount: number; skuCount: number }> {
  const data = await loadData();
  if (!data?.bySku) {
    return { loaded: false, styleCount: 0, skuCount: 0 };
  }

  const styles = buildStylesIndex(data);
  stylesList = Array.from(styles.values());

  return {
    loaded: true,
    styleCount: styles.size,
    skuCount: Object.keys(data.bySku).length,
  };
}

import { NextResponse } from "next/server";
import { getTechfeedWheelBySku } from "@/lib/techfeed/wheels";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";
export const revalidate = 0;

// Simple in-memory cache (best-effort; per-server instance).
// Helps a lot because WheelPros responses are relatively static.
const CACHE_TTL_MS = 10 * 60 * 1000;
const cache = new Map<
  string,
  { expiresAt: number; status: number; headers: Record<string, string>; data: any }
>();

type WheelProsSearchResponse = {
  results?: any[];
  [k: string]: any;
};

function toWheelProsImages(urls: string[]) {
  return urls
    .filter(Boolean)
    .map((u) => ({
      imageUrlLarge: u,
      imageUrlMedium: u,
      imageUrlSmall: u,
      imageUrlThumbnail: u,
    }));
}

function hasAnyImage(it: any) {
  const imgs = Array.isArray(it?.images) ? it.images : [];
  return imgs.some((img: any) => {
    const u =
      img?.imageUrlLarge ||
      img?.imageUrlMedium ||
      img?.imageUrlOriginal ||
      img?.imageUrlSmall ||
      img?.imageUrlThumbnail;
    return typeof u === "string" && u.trim().length > 0;
  });
}

export async function GET(req: Request) {
  const url = new URL(req.url);
  const debug = url.searchParams.get("debug") === "1" || process.env.WT_DIAGNOSTICS === "1";
  const t0 = debug ? Date.now() : 0;
  const base =
    process.env.WHEELPROS_WRAPPER_URL ||
    process.env.NEXT_PUBLIC_WHEELPROS_API_BASE_URL;
  if (!base) {
    return NextResponse.json(
      { error: "Missing WHEELPROS_WRAPPER_URL (or NEXT_PUBLIC_WHEELPROS_API_BASE_URL)" },
      { status: 500 }
    );
  }

  const upstream = new URL("/wheels/search", base);
  url.searchParams.forEach((v, k) => upstream.searchParams.set(k, v));

  const headers: Record<string, string> = { Accept: "application/json" };
  if (process.env.WHEELPROS_WRAPPER_API_KEY) {
    headers["x-api-key"] = process.env.WHEELPROS_WRAPPER_API_KEY;
  }

  const cacheKey = upstream.toString();
  const cached = cache.get(cacheKey);
  if (cached && cached.expiresAt > Date.now()) {
    const totalMs = debug ? Date.now() - t0 : 0;
    if (debug) {
      try {
        console.info("[api wheelpros/wheels/search] HIT", {
          totalMs,
          q: url.searchParams.get("q") || "",
          sku: url.searchParams.get("sku") || "",
          brand_cd: url.searchParams.get("brand_cd") || "",
          boltPattern: url.searchParams.get("boltPattern") || "",
          diameter: url.searchParams.get("diameter") || "",
          width: url.searchParams.get("width") || "",
          page: url.searchParams.get("page") || "",
          pageSize: url.searchParams.get("pageSize") || "",
        });
      } catch {
        // ignore
      }
    }

    return NextResponse.json(cached.data, {
      status: cached.status,
      headers: {
        "content-type": cached.headers["content-type"] || "application/json",
        "x-wt-cache": "HIT",
        ...(debug
          ? {
              "x-wt-total-ms": String(totalMs),
              "server-timing": `total;dur=${totalMs}`,
            }
          : null),
      },
    });
  }

  const tUp0 = debug ? Date.now() : 0;
  const res = await fetch(upstream.toString(), { headers, cache: "no-store" });
  const upstreamMs = debug ? Date.now() - tUp0 : 0;
  const ct = res.headers.get("content-type") || "application/json";

  let data: WheelProsSearchResponse | null = null;
  try {
    data = (await res.json()) as WheelProsSearchResponse;
  } catch {
    // If upstream didn't return JSON for some reason, just proxy through.
    const text = await res.text();
    return new NextResponse(text, { status: res.status, headers: { "content-type": ct } });
  }

  let enrichMs = debug ? 0 : 0;
  if (res.ok && data?.results?.length) {
    const tEn0 = debug ? Date.now() : 0;
    const enriched = await Promise.all(
      data.results.map(async (it) => {
        const sku = it?.sku ? String(it.sku) : "";
        if (!sku) return it;

        const tf = await getTechfeedWheelBySku(sku);
        if (!tf) return it;

        // Attach techfeed metadata for UI grouping.
        (it as any).techfeed = {
          style: tf.style || tf.display_style_no || "",
          finish:
            tf.abbreviated_finish_desc ||
            tf.fancy_finish_desc ||
            tf.box_label_desc ||
            tf.product_desc ||
            "",
          images: tf.images || [],
        };

        // Ensure properties are populated (WheelPros API sometimes returns blanks).
        it.properties = it.properties || {};
        if (tf.diameter && !it.properties.diameter) it.properties.diameter = tf.diameter;
        if (tf.width && !it.properties.width) it.properties.width = tf.width;
        if (tf.offset && !it.properties.offset) it.properties.offset = tf.offset;
        if (tf.centerbore && !it.properties.centerbore) it.properties.centerbore = tf.centerbore;

        // bolt patterns
        if (tf.bolt_pattern_metric && !it.properties.boltPatternMetric)
          it.properties.boltPatternMetric = tf.bolt_pattern_metric;
        if (tf.bolt_pattern_standard && !it.properties.boltPattern)
          it.properties.boltPattern = tf.bolt_pattern_standard;

        // finish (best effort)
        if (tf.abbreviated_finish_desc && !it.properties.finish)
          it.properties.finish = tf.abbreviated_finish_desc;

        // MSRP: you asked to apply MSRP for WheelPros wheels.
        if (tf.msrp) {
          it.prices = it.prices || {};
          it.prices.msrp = [{ currencyAmount: String(tf.msrp), currencyCode: "USD" }];
        }

        // Images: use techfeed when WheelPros images are missing.
        const urls = tf.images || [];
        if (urls.length && (!Array.isArray(it.images) || it.images.length === 0)) {
          it.images = toWheelProsImages(urls);
        }

        return it;
      })
    );

    // Remove products that have no images at all.
    // NOTE: Only do this when the caller is applying some kind of search/filter.
    // A completely unfiltered WheelPros browse can legitimately return many items
    // without images (or omit image fields), which would otherwise yield 0 results.
    enrichMs = debug ? Date.now() - tEn0 : 0;

    const sp = url.searchParams;
    // Only hide no-image items for explicitly targeted searches.
    // If we hide no-image items for fitment-derived filters (bolt pattern/diameter/offset),
    // we can drastically undercount results vs DealerLineX because WheelPros often omits
    // image fields even for valid SKUs.
    const shouldFilterNoImage = sp.has("sku") || sp.has("q") || sp.has("brand_cd");

    if (shouldFilterNoImage) {
      const filtered = enriched.filter((it) => hasAnyImage(it));

      // Heuristic: don't let the "hide no-image" filter collapse a page to only a couple
      // of results (WheelPros sometimes omits image fields even for valid SKUs).
      // If filtering would leave too few items, keep the unfiltered enriched list.
      const minKeep = Math.min(8, enriched.length);
      data.results = filtered.length >= minKeep ? filtered : enriched;
    } else {
      data.results = enriched;
    }
  }

  const totalMs = debug ? Date.now() - t0 : 0;

  if (debug) {
    try {
      console.info("[api wheelpros/wheels/search] MISS", {
        status: res.status,
        upstreamMs,
        enrichMs,
        totalMs,
        q: url.searchParams.get("q") || "",
        sku: url.searchParams.get("sku") || "",
        brand_cd: url.searchParams.get("brand_cd") || "",
        boltPattern: url.searchParams.get("boltPattern") || "",
        diameter: url.searchParams.get("diameter") || "",
        width: url.searchParams.get("width") || "",
        page: url.searchParams.get("page") || "",
        pageSize: url.searchParams.get("pageSize") || "",
        results: Array.isArray(data?.results) ? data.results.length : null,
      });
    } catch {
      // ignore
    }
  }

  const out = NextResponse.json(data, {
    status: res.status,
    headers: {
      "content-type": "application/json",
      "x-wt-cache": "MISS",
      ...(debug
        ? {
            "x-wt-upstream-ms": String(upstreamMs),
            "x-wt-enrich-ms": String(enrichMs),
            "x-wt-total-ms": String(totalMs),
            "server-timing": `upstream;dur=${upstreamMs}, enrich;dur=${enrichMs}, total;dur=${totalMs}`,
          }
        : null),
    },
  });

  // Cache only successful JSON bodies.
  if (res.ok && data) {
    cache.set(cacheKey, {
      expiresAt: Date.now() + CACHE_TTL_MS,
      status: res.status,
      headers: { "content-type": "application/json" },
      data,
    });

    // basic cap
    if (cache.size > 200) {
      const firstKey = cache.keys().next().value;
      if (firstKey) cache.delete(firstKey);
    }
  }

  return out;
}

/**
 * Vehicle Fitment Engine
 * Uses Wheel-Size API data as source of truth for strict wheel validation
 */
import pg from "pg";
import { normalizeModelForApi, normalizeMake } from "./fitment-db/keys";

const { Pool } = pg;

// ─────────────────────────────────────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────────────────────────────────────

export type Vehicle = {
  id: number;
  year: number;
  make: string;
  model: string;
  trim: string | null;
  slug: string | null; // Wheel-Size modification slug
  createdAt: Date;
  updatedAt: Date;
};

export type VehicleFitment = {
  id: number;
  vehicleId: number;
  boltPattern: string;       // e.g., "6x135"
  centerBore: number;        // mm, e.g., 87.1
  studHoles: number;         // e.g., 6
  pcd: number;               // mm, e.g., 135
  threadSize: string | null; // e.g., "M14x1.5"
  fastenerType: string | null; // "lug_nut" | "lug_bolt"
  torqueNm: number | null;
  createdAt: Date;
  updatedAt: Date;
};

export type VehicleWheelSpec = {
  id: number;
  vehicleId: number;
  rimDiameter: number;       // inches, e.g., 17
  rimWidth: number;          // inches, e.g., 7.5
  offset: number | null;     // mm, e.g., 44 (can be null for some plus sizes)
  tireSize: string | null;   // e.g., "265/70R17"
  axle: "front" | "rear" | "both";  // which axle this spec is for
  isStock: boolean;
  createdAt: Date;
  updatedAt: Date;
};

export type StaggeredInfo = {
  isStaggered: boolean;
  reason: string;
  frontSpec?: {
    diameter: number;
    width: number;
    offset: number | null;
    tireSize: string | null;
  };
  rearSpec?: {
    diameter: number;
    width: number;
    offset: number | null;
    tireSize: string | null;
  };
};

export type FitmentProfile = {
  vehicle: Vehicle;
  fitment: VehicleFitment;
  wheelSpecs: VehicleWheelSpec[];
  // Derived allowed values
  allowedDiameters: number[];
  allowedWidths: number[];
  allowedOffsets: number[];
  boltPattern: string;
  centerBore: number;
  // Staggered fitment info
  staggered: StaggeredInfo;
};

export type FitmentClass = "surefit" | "specfit" | "excluded";

export type WheelValidation = {
  sku: string;
  boltPatternPass: boolean;
  centerBorePass: boolean;
  diameterPass: boolean;
  widthPass: boolean;
  offsetPass: boolean;
  fitmentClass: FitmentClass;
  exclusionReasons: string[];
};

export type WheelToValidate = {
  sku: string;
  boltPattern?: string;
  centerBore?: number;
  diameter?: number;
  width?: number;
  offset?: number;
};

// ─────────────────────────────────────────────────────────────────────────────
// DATABASE CONNECTION
// ─────────────────────────────────────────────────────────────────────────────

let pool: pg.Pool | null = null;

export function getPool(): pg.Pool {
  if (pool) return pool;
  pool = new Pool({
    connectionString: process.env.DATABASE_URL,
    max: 5,
  });
  return pool;
}

// ─────────────────────────────────────────────────────────────────────────────
// SCHEMA INITIALIZATION
// ─────────────────────────────────────────────────────────────────────────────

export async function ensureFitmentTables(db: pg.Pool): Promise<void> {
  await db.query(`
    CREATE TABLE IF NOT EXISTS vehicles (
      id SERIAL PRIMARY KEY,
      year INTEGER NOT NULL,
      make VARCHAR(100) NOT NULL,
      model VARCHAR(100) NOT NULL,
      trim VARCHAR(100),
      search_trim VARCHAR(100),
      slug VARCHAR(255), -- Wheel-Size modification slug
      market_regions VARCHAR(255),
      imported_from VARCHAR(50),
      imported_at TIMESTAMP WITH TIME ZONE,
      import_status VARCHAR(20),
      last_import_error TEXT,
      last_import_attempt_at TIMESTAMP WITH TIME ZONE,
      created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
      updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
      UNIQUE(year, make, model, trim)
    );

    CREATE TABLE IF NOT EXISTS vehicle_fitment (
      id SERIAL PRIMARY KEY,
      vehicle_id INTEGER NOT NULL REFERENCES vehicles(id) ON DELETE CASCADE,
      bolt_pattern VARCHAR(20) NOT NULL,
      center_bore DECIMAL(6,2) NOT NULL,
      stud_holes INTEGER NOT NULL,
      pcd DECIMAL(6,2) NOT NULL,
      thread_size VARCHAR(20),
      fastener_type VARCHAR(20),
      torque_nm INTEGER,
      imported_at TIMESTAMP WITH TIME ZONE,
      created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
      updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
      UNIQUE(vehicle_id)
    );

    CREATE TABLE IF NOT EXISTS vehicle_wheel_specs (
      id SERIAL PRIMARY KEY,
      vehicle_id INTEGER NOT NULL REFERENCES vehicles(id) ON DELETE CASCADE,
      rim_diameter DECIMAL(4,1) NOT NULL,
      rim_width DECIMAL(4,2) NOT NULL,
      "offset" DECIMAL(5,2),
      tire_size VARCHAR(30),
      axle VARCHAR(10) DEFAULT 'both',  -- front, rear, or both
      is_stock BOOLEAN DEFAULT true,
      imported_at TIMESTAMP WITH TIME ZONE,
      created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
      updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
    );

    CREATE INDEX IF NOT EXISTS idx_vehicles_year_make_model ON vehicles(year, make, model);
    CREATE INDEX IF NOT EXISTS idx_vehicles_year_make_model_slug ON vehicles(year, make, model, slug);
    CREATE INDEX IF NOT EXISTS idx_vehicle_wheel_specs_vehicle_id ON vehicle_wheel_specs(vehicle_id);

    -- Allow NULL offset for existing tables
    ALTER TABLE vehicle_wheel_specs ALTER COLUMN "offset" DROP NOT NULL;

    -- Change offset from INTEGER to DECIMAL for API values like 44.45
    ALTER TABLE vehicle_wheel_specs ALTER COLUMN "offset" TYPE DECIMAL(5,2) USING "offset"::DECIMAL(5,2);

    -- Add missing columns for existing deployments (safe no-ops if present)
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS search_trim VARCHAR(100);
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS market_regions VARCHAR(255);
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS imported_from VARCHAR(50);
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS imported_at TIMESTAMP WITH TIME ZONE;
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS import_status VARCHAR(20);
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS last_import_error TEXT;
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS last_import_attempt_at TIMESTAMP WITH TIME ZONE;

    ALTER TABLE vehicle_fitment ADD COLUMN IF NOT EXISTS imported_at TIMESTAMP WITH TIME ZONE;
    ALTER TABLE vehicle_wheel_specs ADD COLUMN IF NOT EXISTS imported_at TIMESTAMP WITH TIME ZONE;
    ALTER TABLE vehicle_wheel_specs ADD COLUMN IF NOT EXISTS axle VARCHAR(10) DEFAULT 'both';

    -- Ensure uniqueness for caching: year/make/model/modification_slug (vehicles.slug)
    DO $$
    BEGIN
      IF NOT EXISTS (
        SELECT 1 FROM pg_constraint WHERE conname = 'vehicles_year_make_model_slug_unique'
      ) THEN
        ALTER TABLE vehicles ADD CONSTRAINT vehicles_year_make_model_slug_unique UNIQUE (year, make, model, slug);
      END IF;
    END$$;
  `);
}

