        placeholder={placeholder}
        className="w-full h-9 rounded-lg bg-neutral-700 border border-neutral-600 px-3 text-white text-sm"
      />
    </div>
  );
}

function DataItem({ label, value }: { label: string; value: string | null | undefined }) {
