import Link from "next/link";
import pg from "pg";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

const { Pool } = pg;

function getPool() {
  const url = process.env.DATABASE_URL || process.env.POSTGRES_URL;
  if (!url) throw new Error("Missing DATABASE_URL");
  return new Pool({
    connectionString: url,
    ssl: { rejectUnauthorized: false },
    max: 3,
  });
}

async function getStats() {
  const pool = getPool();
  try {
    const [todayRes, weekRes, totalRes, flaggedRes, errorsRes, issuesRes] = await Promise.all([
      pool.query(`SELECT COUNT(*) as count FROM quotes WHERE created_at >= CURRENT_DATE`),
      pool.query(`SELECT COUNT(*) as count FROM quotes WHERE created_at >= CURRENT_DATE - INTERVAL '7 days'`),
      pool.query(`SELECT COUNT(*) as count FROM quotes`),
      pool.query(`SELECT COUNT(*) as count FROM admin_product_flags WHERE flagged = true`),
      pool.query(`SELECT COUNT(*) as count FROM admin_logs WHERE log_type = 'search_error' AND created_at >= CURRENT_DATE - INTERVAL '24 hours'`),
      pool.query(`
        SELECT 
          COALESCE(SUM(CASE WHEN log_type = 'search_error' THEN 1 ELSE 0 END), 0) as search_errors,
          COALESCE(SUM(CASE WHEN log_type = 'warning' THEN 1 ELSE 0 END), 0) as warnings,
          COALESCE(SUM(CASE WHEN log_type = 'fitment' AND details->>'quality' = 'invalid' THEN 1 ELSE 0 END), 0) as fitment_issues
        FROM admin_logs 
        WHERE created_at >= CURRENT_DATE - INTERVAL '24 hours'
      `),
    ]);

    // Get recent logs for issues panel
    const recentIssuesRes = await pool.query(`
      SELECT log_type, vehicle_params, details, created_at
      FROM admin_logs
      WHERE log_type IN ('search_error', 'warning', 'fitment')
        AND created_at >= CURRENT_DATE - INTERVAL '24 hours'
      ORDER BY created_at DESC
      LIMIT 10
    `);

    // Get performance metrics from logs
    const perfRes = await pool.query(`
      SELECT 
        AVG((details->>'searchTimeMs')::numeric) as avg_search_time,
        MAX((details->>'searchTimeMs')::numeric) as max_search_time,
        COUNT(*) as total_searches
      FROM admin_logs
      WHERE log_type = 'fitment' 
        AND details->>'searchTimeMs' IS NOT NULL
        AND created_at >= CURRENT_DATE - INTERVAL '24 hours'
    `);

    return {
      ordersToday: parseInt(todayRes.rows[0]?.count || "0", 10),
      ordersWeek: parseInt(weekRes.rows[0]?.count || "0", 10),
      ordersTotal: parseInt(totalRes.rows[0]?.count || "0", 10),
      flaggedProducts: parseInt(flaggedRes.rows[0]?.count || "0", 10),
      recentErrors: parseInt(errorsRes.rows[0]?.count || "0", 10),
      issues: {
        searchErrors: parseInt(issuesRes.rows[0]?.search_errors || "0", 10),
        warnings: parseInt(issuesRes.rows[0]?.warnings || "0", 10),
        fitmentIssues: parseInt(issuesRes.rows[0]?.fitment_issues || "0", 10),
      },
      recentIssues: recentIssuesRes.rows,
      performance: {
        avgSearchTime: Math.round(parseFloat(perfRes.rows[0]?.avg_search_time || "0")),
        maxSearchTime: Math.round(parseFloat(perfRes.rows[0]?.max_search_time || "0")),
        totalSearches: parseInt(perfRes.rows[0]?.total_searches || "0", 10),
      },
    };
  } catch (err) {
    console.error("[admin] Error fetching stats:", err);
    return {
      ordersToday: 0,
      ordersWeek: 0,
      ordersTotal: 0,
      flaggedProducts: 0,
      recentErrors: 0,
      issues: { searchErrors: 0, warnings: 0, fitmentIssues: 0 },
      recentIssues: [],
      performance: { avgSearchTime: 0, maxSearchTime: 0, totalSearches: 0 },
    };
  } finally {
    await pool.end();
  }
}

export default async function AdminDashboard() {
  const stats = await getStats();
  const totalIssues = stats.issues.searchErrors + stats.issues.warnings + stats.issues.fitmentIssues;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-white">Dashboard</h1>
        <p className="text-neutral-400 mt-1">Welcome to the admin portal</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
        <StatCard
          icon="📦"
          label="Orders Today"
          value={stats.ordersToday}
          href="/admin/orders?filter=today"
        />
        <StatCard
          icon="📅"
          label="Orders This Week"
          value={stats.ordersWeek}
          href="/admin/orders?filter=week"
        />
        <StatCard
          icon="📊"
          label="Total Orders"
          value={stats.ordersTotal}
          href="/admin/orders"
        />
        <StatCard
          icon="⚠️"
          label="Flagged Products"
          value={stats.flaggedProducts}
          href="/admin/products?filter=flagged"
          alert={stats.flaggedProducts > 0}
        />
        <StatCard
          icon="🚨"
          label="Issues (24h)"
          value={totalIssues}
          href="/admin/logs"
          alert={totalIssues > 0}
        />
      </div>

      {/* Performance & Issues Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Performance Metrics */}
        <div className="bg-neutral-800 rounded-xl border border-neutral-700 p-6">
          <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
            <span>📈</span> Performance (24h)
          </h2>
          <div className="grid grid-cols-3 gap-4">
            <MetricCard
              label="Avg Search"
              value={stats.performance.avgSearchTime > 0 ? `${stats.performance.avgSearchTime}ms` : "—"}
              status={stats.performance.avgSearchTime < 1000 ? "good" : stats.performance.avgSearchTime < 3000 ? "warn" : "bad"}
            />
            <MetricCard
              label="Max Search"
              value={stats.performance.maxSearchTime > 0 ? `${stats.performance.maxSearchTime}ms` : "—"}
              status={stats.performance.maxSearchTime < 3000 ? "good" : stats.performance.maxSearchTime < 5000 ? "warn" : "bad"}
            />
            <MetricCard
              label="Total Searches"
              value={stats.performance.totalSearches.toString()}
              status="neutral"
            />
          </div>
        </div>

        {/* Issues Panel */}
        <div className="bg-neutral-800 rounded-xl border border-neutral-700 p-6">
          <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
            <span>🚨</span> Issues (24h)
            {totalIssues > 0 && (
              <span className="text-xs bg-red-600 text-white px-2 py-0.5 rounded-full ml-2">
                {totalIssues}
              </span>
            )}
          </h2>
          {totalIssues === 0 ? (
            <div className="text-neutral-500 text-sm py-4 text-center">
              ✅ No issues in the last 24 hours
            </div>
          ) : (
            <div className="space-y-3">
              <IssueRow
                icon="❌"
                label="Search Errors"
                count={stats.issues.searchErrors}
                href="/admin/logs?type=search_error"
              />
              <IssueRow
                icon="⚠️"
                label="Warnings"
                count={stats.issues.warnings}
                href="/admin/logs?type=warning"
              />
              <IssueRow
                icon="🔧"
                label="Fitment Issues"
                count={stats.issues.fitmentIssues}
                href="/admin/logs?type=fitment"
              />
            </div>
          )}
        </div>
      </div>

      {/* Quick Actions */}
      <div className="bg-neutral-800 rounded-xl border border-neutral-700 p-6">
        <h2 className="text-lg font-bold text-white mb-4">Quick Actions</h2>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <QuickAction
            icon="📦"
            label="View Orders"
            description="See all submitted orders"
            href="/admin/orders"
          />
          <QuickAction
            icon="🔧"
            label="Fitment Overrides"
            description="Edit vehicle fitment data"
            href="/admin/fitment"
          />
          <QuickAction
            icon="🛞"
            label="Product Controls"
            description="Flag or hide products"
            href="/admin/products"
          />
          <QuickAction
            icon="📋"
            label="View Logs"
            description="Check system logs"
            href="/admin/logs"
          />
        </div>
      </div>

      {/* Recent Issues List */}
      {stats.recentIssues.length > 0 && (
        <div className="bg-neutral-800 rounded-xl border border-neutral-700 p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-bold text-white">Recent Issues</h2>
            <Link href="/admin/logs" className="text-sm text-red-400 hover:text-red-300">
              View all →
            </Link>
          </div>
          <div className="space-y-2">
            {stats.recentIssues.slice(0, 5).map((issue: any, i: number) => (
              <RecentIssueItem key={i} issue={issue} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function StatCard({
  icon,
  label,
  value,
  href,
  alert,
}: {
  icon: string;
  label: string;
  value: number;
  href: string;
  alert?: boolean;
}) {
  return (
    <Link
      href={href}
      className={`bg-neutral-800 rounded-xl border p-5 hover:border-neutral-600 transition-colors ${
        alert ? "border-amber-600" : "border-neutral-700"
      }`}
    >
      <div className="flex items-start justify-between">
        <span className="text-2xl">{icon}</span>
        {alert && <span className="text-amber-500 text-xs font-bold">!</span>}
      </div>
      <div className="mt-3">
        <div className="text-3xl font-bold text-white">{value}</div>
        <div className="text-sm text-neutral-400 mt-1">{label}</div>
      </div>
    </Link>
  );
}

function MetricCard({
  label,
  value,
  status,
}: {
  label: string;
  value: string;
  status: "good" | "warn" | "bad" | "neutral";
}) {
  const statusColors = {
    good: "text-green-400",
    warn: "text-amber-400",
    bad: "text-red-400",
    neutral: "text-white",
  };

  return (
    <div className="text-center">
      <div className={`text-2xl font-bold ${statusColors[status]}`}>{value}</div>
      <div className="text-xs text-neutral-500 mt-1">{label}</div>
    </div>
  );
}

function IssueRow({
  icon,
  label,
  count,
  href,
}: {
  icon: string;
  label: string;
  count: number;
  href: string;
}) {
  if (count === 0) return null;

  return (
    <Link
      href={href}
      className="flex items-center justify-between p-2 rounded-lg hover:bg-neutral-700/50 transition-colors"
    >
      <div className="flex items-center gap-2">
        <span>{icon}</span>
        <span className="text-sm text-neutral-300">{label}</span>
      </div>
      <span className="text-sm font-bold text-red-400">{count}</span>
    </Link>
  );
}

function QuickAction({
  icon,
  label,
  description,
  href,
}: {
  icon: string;
  label: string;
  description: string;
  href: string;
}) {
  return (
    <Link
      href={href}
      className="bg-neutral-700/50 rounded-xl p-4 hover:bg-neutral-700 transition-colors group"
    >
      <div className="flex items-center gap-3">
        <span className="text-2xl">{icon}</span>
        <div>
          <div className="font-semibold text-white group-hover:text-red-400 transition-colors">
            {label}
          </div>
          <div className="text-xs text-neutral-400">{description}</div>
        </div>
      </div>
    </Link>
  );
}

function RecentIssueItem({ issue }: { issue: any }) {
  const icons: Record<string, string> = {
    search_error: "❌",
    warning: "⚠️",
    fitment: "🔧",
  };

  const vehicle = issue.vehicle_params
    ? `${issue.vehicle_params.year || ""} ${issue.vehicle_params.make || ""} ${issue.vehicle_params.model || ""}`.trim()
    : null;

  const message = issue.details?.error || issue.details?.message || issue.log_type;
  const time = new Date(issue.created_at).toLocaleTimeString("en-US", {
    hour: "numeric",
    minute: "2-digit",
  });

  return (
    <div className="flex items-start gap-3 p-2 rounded-lg bg-neutral-700/30">
      <span className="text-lg">{icons[issue.log_type] || "📋"}</span>
      <div className="flex-1 min-w-0">
        <div className="text-sm text-white truncate">{message}</div>
        {vehicle && (
          <div className="text-xs text-neutral-500">{vehicle}</div>
        )}
      </div>
      <div className="text-xs text-neutral-500">{time}</div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";

type ProductFlag = {
  id: string;
  product_type: string;
  sku: string;
  hidden: boolean;
  flagged: boolean;
  flag_reason: string | null;
  image_url: string | null;
  created_at: string;
  updated_at: string;
};

type Counts = {
  hidden_count: string;
  flagged_count: string;
  total_count: string;
  missing_image_count: string;
};

export default function ProductsPage() {
  const [products, setProducts] = useState<ProductFlag[]>([]);
  const [counts, setCounts] = useState<Counts | null>(null);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<"all" | "flagged" | "hidden" | "missing_image">("all");
  const [productType, setProductType] = useState<"wheel" | "tire" | "">("");
  const [search, setSearch] = useState("");
  const [addingSku, setAddingSku] = useState("");

  // Image edit state
  const [editingImage, setEditingImage] = useState<string | null>(null);
  const [imageUrl, setImageUrl] = useState("");

  const fetchProducts = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (productType) params.set("type", productType);
      if (filter !== "all") params.set("filter", filter);
      if (search) params.set("search", search);

      const res = await fetch(`/api/admin/products?${params.toString()}`);
      const data = await res.json();

      setProducts(data.products || []);
      setCounts(data.counts || null);
    } catch (err) {
      console.error("Failed to fetch products:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, [filter, productType]);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    fetchProducts();
  };

  const handleAddSku = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!addingSku || !productType) return;

    try {
      await fetch("/api/admin/products", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productType,
          sku: addingSku,
          flagged: true,
          flagReason: "Manually flagged",
        }),
      });
      setAddingSku("");
      fetchProducts();
    } catch (err) {
      alert("Failed to add SKU");
    }
  };

  const handleToggle = async (product: ProductFlag, field: "hidden" | "flagged") => {
    try {
      await fetch("/api/admin/products", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productType: product.product_type,
          sku: product.sku,
          hidden: field === "hidden" ? !product.hidden : product.hidden,
          flagged: field === "flagged" ? !product.flagged : product.flagged,
          flagReason: product.flag_reason,
          imageUrl: product.image_url,
        }),
      });
      fetchProducts();
    } catch (err) {
      alert("Failed to update");
    }
  };

  const handleSaveImage = async (product: ProductFlag) => {
    try {
      await fetch("/api/admin/products", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productType: product.product_type,
          sku: product.sku,
          hidden: product.hidden,
          flagged: product.flagged,
          flagReason: product.flag_reason,
          imageUrl: imageUrl || null,
        }),
      });
      setEditingImage(null);
      setImageUrl("");
      fetchProducts();
    } catch (err) {
      alert("Failed to save image URL");
    }
  };

  const handleDelete = async (product: ProductFlag) => {
    if (!confirm("Remove this product flag? It will appear normally in search.")) return;

    try {
      await fetch(`/api/admin/products?type=${product.product_type}&sku=${product.sku}`, {
        method: "DELETE",
      });
      fetchProducts();
    } catch (err) {
      alert("Failed to delete");
    }
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-white">Product Controls</h1>
        <p className="text-neutral-400 mt-1">
          Hide, flag, or fix images for products
        </p>
      </div>

      {/* Stats */}
      {counts && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <StatCard
            label="Total Flagged"
            value={parseInt(counts.flagged_count)}
            color="amber"
          />
          <StatCard
            label="Hidden"
            value={parseInt(counts.hidden_count)}
            color="red"
          />
          <StatCard
            label="Missing Images"
            value={parseInt(counts.missing_image_count || "0")}
            color="orange"
          />
          <StatCard
            label="Total Tracked"
            value={parseInt(counts.total_count)}
            color="neutral"
          />
        </div>
      )}

      {/* Filters */}
      <div className="bg-neutral-800 rounded-xl border border-neutral-700 p-4">
        <div className="flex flex-wrap items-center gap-4">
          {/* Product Type */}
          <div className="flex items-center gap-2">
            <span className="text-sm text-neutral-400">Type:</span>
            <select
              value={productType}
              onChange={(e) => setProductType(e.target.value as any)}
              className="h-9 rounded-lg bg-neutral-700 border border-neutral-600 px-3 text-white text-sm"
            >
              <option value="">All</option>
              <option value="wheel">Wheels</option>
              <option value="tire">Tires</option>
            </select>
          </div>

          {/* Filter */}
          <div className="flex items-center gap-2">
            <span className="text-sm text-neutral-400">Filter:</span>
            <div className="flex rounded-lg overflow-hidden border border-neutral-600">
              {(["all", "flagged", "hidden", "missing_image"] as const).map((f) => (
                <button
                  key={f}
                  onClick={() => setFilter(f)}
                  className={`px-3 py-1.5 text-sm font-medium whitespace-nowrap ${
                    filter === f
                      ? "bg-red-600 text-white"
                      : "bg-neutral-700 text-neutral-300 hover:bg-neutral-600"
                  }`}
                >
                  {f === "missing_image" ? "Missing Image" : f.charAt(0).toUpperCase() + f.slice(1)}
                </button>
              ))}
            </div>
          </div>

          {/* Search */}
          <form onSubmit={handleSearch} className="flex items-center gap-2 flex-1">
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search SKU..."
              className="flex-1 h-9 rounded-lg bg-neutral-700 border border-neutral-600 px-3 text-white text-sm min-w-[200px]"
            />
            <button
              type="submit"
              className="h-9 px-4 rounded-lg bg-neutral-600 text-white text-sm font-medium hover:bg-neutral-500"
            >
              Search
            </button>
          </form>
        </div>

        {/* Add SKU */}
        {productType && (
          <form onSubmit={handleAddSku} className="mt-4 pt-4 border-t border-neutral-700 flex items-center gap-2">
            <input
              type="text"
              value={addingSku}
              onChange={(e) => setAddingSku(e.target.value)}
              placeholder={`Add ${productType} SKU to flag...`}
              className="flex-1 h-9 rounded-lg bg-neutral-700 border border-neutral-600 px-3 text-white text-sm"
            />
            <button
              type="submit"
              disabled={!addingSku}
              className="h-9 px-4 rounded-lg bg-amber-600 text-white text-sm font-medium hover:bg-amber-700 disabled:opacity-50"
            >
              Flag SKU
            </button>
          </form>
        )}
