import { NextResponse } from "next/server";
import pg from "pg";

export const runtime = "nodejs";

const { Pool } = pg;

function getPool() {
  const url = process.env.DATABASE_URL || process.env.POSTGRES_URL;
  if (!url) throw new Error("Missing DATABASE_URL");
  return new Pool({
    connectionString: url,
    ssl: { rejectUnauthorized: false },
    max: 3,
  });
}

/**
 * Search actual products (wheels/tires) from cache tables
 * Returns products with their flag status
 */
export async function GET(req: Request) {
  const url = new URL(req.url);
  const query = url.searchParams.get("q") || "";
  const productType = url.searchParams.get("type") || "wheel";
  const supplier = url.searchParams.get("supplier");
  const brand = url.searchParams.get("brand");
  const limit = Math.min(100, parseInt(url.searchParams.get("limit") || "50", 10));

  if (!query || query.length < 2) {
    return NextResponse.json({ 
      products: [], 
      message: "Enter at least 2 characters to search" 
    });
  }

  const pool = getPool();
  try {
    // Ensure image_url column exists
    await pool.query(`
      ALTER TABLE admin_product_flags ADD COLUMN IF NOT EXISTS image_url TEXT
    `).catch(() => {});

    // Add supplier/brand columns if missing
    await pool.query(`
      ALTER TABLE admin_product_flags ADD COLUMN IF NOT EXISTS supplier TEXT
    `).catch(() => {});
    await pool.query(`
      ALTER TABLE admin_product_flags ADD COLUMN IF NOT EXISTS brand TEXT
    `).catch(() => {});

    if (productType === "wheel") {
      // Search wheel_cache for wheels
      const { rows } = await pool.query(`
        SELECT 
          wc.sku,
          wc.upc,
          wc.style_description as name,
          wc.brand,
          wc.finish as finish_desc,
          wc.diameter,
          wc.width,
          wc.bolt_pattern,
          wc.offset,
          wc.image_url,
          wc.supplier,
          pf.id as flag_id,
          pf.hidden,
          pf.flagged,
          pf.flag_reason,
          pf.image_url as override_image_url
        FROM wheel_cache wc
        LEFT JOIN admin_product_flags pf ON pf.sku = wc.sku AND pf.product_type = 'wheel'
        WHERE (
          wc.sku ILIKE $1 
          OR wc.upc ILIKE $1
          OR wc.style_description ILIKE $1
          OR wc.brand ILIKE $1
        )
        ${supplier ? `AND wc.supplier = $3` : ""}
        ${brand ? `AND wc.brand ILIKE ${supplier ? "$4" : "$3"}` : ""}
        ORDER BY wc.brand, wc.style_description
        LIMIT $2
      `, supplier && brand 
        ? [`%${query}%`, limit, supplier, `%${brand}%`]
        : supplier 
          ? [`%${query}%`, limit, supplier]
          : brand 
            ? [`%${query}%`, limit, `%${brand}%`]
            : [`%${query}%`, limit]
      );

      // Get distinct brands/suppliers for filters
      const { rows: brandRows } = await pool.query(`
        SELECT DISTINCT brand FROM wheel_cache WHERE brand IS NOT NULL ORDER BY brand LIMIT 100
      `);
      const { rows: supplierRows } = await pool.query(`
        SELECT DISTINCT supplier FROM wheel_cache WHERE supplier IS NOT NULL ORDER BY supplier
      `);

      return NextResponse.json({
        products: rows.map(r => ({
          sku: r.sku,
          upc: r.upc,
          name: r.name,
          brand: r.brand,
          finish: r.finish_desc,
          size: r.diameter && r.width ? `${r.diameter}x${r.width}` : null,
          boltPattern: r.bolt_pattern,
          offset: r.offset,
          imageUrl: r.override_image_url || r.image_url,
          supplier: r.supplier,
          // Flag status
          flagId: r.flag_id,
          hidden: r.hidden || false,
          flagged: r.flagged || false,
          flagReason: r.flag_reason,
        })),
        filters: {
          brands: brandRows.map(r => r.brand),
          suppliers: supplierRows.map(r => r.supplier),
        },
        total: rows.length,
      });
    } else {
      // For tires, search tire_cache if it exists, otherwise return empty
      try {
        const { rows } = await pool.query(`
          SELECT 
            tc.sku,
            tc.name,
            tc.brand,
            tc.size,
            tc.image_url,
            tc.supplier,
            pf.id as flag_id,
            pf.hidden,
            pf.flagged,
            pf.flag_reason,
            pf.image_url as override_image_url
          FROM tire_cache tc
          LEFT JOIN admin_product_flags pf ON pf.sku = tc.sku AND pf.product_type = 'tire'
          WHERE (
            tc.sku ILIKE $1 
            OR tc.name ILIKE $1
            OR tc.brand ILIKE $1
          )
          ORDER BY tc.brand, tc.name
          LIMIT $2
        `, [`%${query}%`, limit]);

        return NextResponse.json({
          products: rows.map(r => ({
            sku: r.sku,
            name: r.name,
            brand: r.brand,
            size: r.size,
            imageUrl: r.override_image_url || r.image_url,
            supplier: r.supplier,
            flagId: r.flag_id,
            hidden: r.hidden || false,
            flagged: r.flagged || false,
            flagReason: r.flag_reason,
          })),
          filters: { brands: [], suppliers: [] },
          total: rows.length,
        });
      } catch {
        // tire_cache doesn't exist
        return NextResponse.json({
          products: [],
          filters: { brands: [], suppliers: [] },
          message: "Tire cache not available",
        });
      }
    }
  } catch (err: any) {
    console.error("[admin/products/search] Error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  } finally {
    await pool.end();
  }
}

import { NextResponse } from "next/server";
import pg from "pg";

export const runtime = "nodejs";

const { Pool } = pg;

function getPool() {
  const url = process.env.DATABASE_URL || process.env.POSTGRES_URL;
  if (!url) throw new Error("Missing DATABASE_URL");
  return new Pool({
    connectionString: url,
    ssl: { rejectUnauthorized: false },
    max: 3,
  });
}

/**
 * Bulk actions on products
 * 
 * Actions:
 * - hide: Hide selected products from search
 * - unhide: Unhide selected products
 * - flag: Flag selected products for review
 * - unflag: Remove flag from selected products
 * - setImage: Set image URL for selected products
 */
export async function POST(req: Request) {
  const body = await req.json();
  const { action, productType, skus, imageUrl, flagReason } = body;

  if (!action || !productType || !skus || !Array.isArray(skus) || skus.length === 0) {
    return NextResponse.json({ 
      error: "action, productType, and skus[] required" 
    }, { status: 400 });
  }

  if (skus.length > 100) {
    return NextResponse.json({ 
      error: "Maximum 100 SKUs per bulk action" 
    }, { status: 400 });
  }

  const validActions = ["hide", "unhide", "flag", "unflag", "setImage"];
  if (!validActions.includes(action)) {
    return NextResponse.json({ 
      error: `Invalid action. Valid: ${validActions.join(", ")}` 
    }, { status: 400 });
  }

  const pool = getPool();
  try {
    // Ensure columns exist
    await pool.query(`
      ALTER TABLE admin_product_flags ADD COLUMN IF NOT EXISTS image_url TEXT
    `).catch(() => {});

    let updated = 0;

    for (const sku of skus) {
      let updateFields: Record<string, any> = {};

      switch (action) {
        case "hide":
          updateFields = { hidden: true };
          break;
        case "unhide":
          updateFields = { hidden: false };
          break;
        case "flag":
          updateFields = { flagged: true, flag_reason: flagReason || "Bulk flagged" };
          break;
        case "unflag":
          updateFields = { flagged: false };
          break;
        case "setImage":
          if (!imageUrl) {
            return NextResponse.json({ error: "imageUrl required for setImage action" }, { status: 400 });
          }
          updateFields = { image_url: imageUrl };
          break;
      }

      // Upsert the flag record
      const setClauses = Object.entries(updateFields)
        .map(([k], i) => `${k} = $${i + 3}`)
        .join(", ");

      const values = [productType, sku, ...Object.values(updateFields)];

      await pool.query(`
        INSERT INTO admin_product_flags (product_type, sku, ${Object.keys(updateFields).join(", ")}, updated_at)
        VALUES ($1, $2, ${Object.values(updateFields).map((_, i) => `$${i + 3}`).join(", ")}, now())
        ON CONFLICT (product_type, sku) DO UPDATE SET
          ${setClauses},
          updated_at = now()
      `, values);

      updated++;
    }

    // Log the bulk action
    await pool.query(`
      INSERT INTO admin_logs (log_type, details)
      VALUES ('bulk_product_action', $1)
    `, [JSON.stringify({ action, productType, skuCount: skus.length, skus: skus.slice(0, 10) })]);

    return NextResponse.json({
      ok: true,
      action,
      updated,
      message: `${action} applied to ${updated} product(s)`,
    });
  } catch (err: any) {
    console.error("[admin/products/bulk] Error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  } finally {
    await pool.end();
  }
}

"use client";

import { useState, useEffect, useCallback } from "react";

type ProductFlag = {
  id: string;
  product_type: string;
  sku: string;
  hidden: boolean;
  flagged: boolean;
  flag_reason: string | null;
  image_url: string | null;
  supplier: string | null;
  brand: string | null;
  created_at: string;
  updated_at: string;
};

type SearchResult = {
  sku: string;
  upc?: string;
  name: string;
  brand: string;
  finish?: string;
  size?: string;
  boltPattern?: string;
  offset?: number;
  imageUrl: string | null;
  supplier: string;
  flagId: string | null;
  hidden: boolean;
  flagged: boolean;
  flagReason: string | null;
};

type Counts = {
  hidden_count: string;
  flagged_count: string;
  total_count: string;
  missing_image_count: string;
};

type ViewMode = "flagged" | "search";

export default function ProductsPage() {
  // View mode
  const [viewMode, setViewMode] = useState<ViewMode>("flagged");

  // Flagged products state
  const [products, setProducts] = useState<ProductFlag[]>([]);
  const [counts, setCounts] = useState<Counts | null>(null);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<"all" | "flagged" | "hidden" | "missing_image">("all");
  const [productType, setProductType] = useState<"wheel" | "tire">("wheel");

  // Search state
  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState<SearchResult[]>([]);
  const [searchLoading, setSearchLoading] = useState(false);
  const [searchFilters, setSearchFilters] = useState<{ brands: string[]; suppliers: string[] }>({ brands: [], suppliers: [] });
  const [selectedBrand, setSelectedBrand] = useState("");
  const [selectedSupplier, setSelectedSupplier] = useState("");

  // Selection state for bulk actions
  const [selectedSkus, setSelectedSkus] = useState<Set<string>>(new Set());
  const [bulkAction, setBulkAction] = useState("");
  const [bulkImageUrl, setBulkImageUrl] = useState("");
  const [bulkLoading, setBulkLoading] = useState(false);

  // Image edit state
  const [editingImage, setEditingImage] = useState<string | null>(null);
  const [imageUrl, setImageUrl] = useState("");

  // Fetch flagged products
  const fetchProducts = useCallback(async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      params.set("type", productType);
      if (filter !== "all") params.set("filter", filter);

      const res = await fetch(`/api/admin/products?${params.toString()}`);
      const data = await res.json();

      setProducts(data.products || []);
      setCounts(data.counts || null);
    } catch (err) {
      console.error("Failed to fetch products:", err);
    } finally {
      setLoading(false);
    }
  }, [filter, productType]);

  // Search products
  const searchProducts = useCallback(async () => {
    if (!searchQuery || searchQuery.length < 2) {
      setSearchResults([]);
      return;
    }

    setSearchLoading(true);
    try {
      const params = new URLSearchParams();
      params.set("q", searchQuery);
      params.set("type", productType);
      if (selectedSupplier) params.set("supplier", selectedSupplier);
      if (selectedBrand) params.set("brand", selectedBrand);

      const res = await fetch(`/api/admin/products/search?${params.toString()}`);
      const data = await res.json();

      setSearchResults(data.products || []);
      if (data.filters) setSearchFilters(data.filters);
    } catch (err) {
      console.error("Failed to search products:", err);
    } finally {
      setSearchLoading(false);
    }
  }, [searchQuery, productType, selectedSupplier, selectedBrand]);

  useEffect(() => {
    if (viewMode === "flagged") {
      fetchProducts();
    }
  }, [viewMode, fetchProducts]);

  useEffect(() => {
    if (viewMode === "search") {
      const timer = setTimeout(searchProducts, 300);
      return () => clearTimeout(timer);
    }
  }, [viewMode, searchQuery, selectedBrand, selectedSupplier, searchProducts]);

  // Toggle selection
  const toggleSelection = (sku: string) => {
    const newSet = new Set(selectedSkus);
    if (newSet.has(sku)) {
      newSet.delete(sku);
    } else {
      newSet.add(sku);
    }
    setSelectedSkus(newSet);
  };

  // Select all visible
  const selectAll = () => {
    const items = viewMode === "flagged" ? products : searchResults;
    const skus = items.map(p => "sku" in p ? p.sku : (p as ProductFlag).sku);
    setSelectedSkus(new Set(skus));
  };

  // Clear selection
  const clearSelection = () => {
    setSelectedSkus(new Set());
  };

  // Execute bulk action
  const executeBulkAction = async () => {
    if (!bulkAction || selectedSkus.size === 0) return;

    setBulkLoading(true);
    try {
      const res = await fetch("/api/admin/products/bulk", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          action: bulkAction,
          productType,
          skus: Array.from(selectedSkus),
          imageUrl: bulkAction === "setImage" ? bulkImageUrl : undefined,
        }),
      });

      const data = await res.json();
      if (data.ok) {
        alert(data.message);
        setSelectedSkus(new Set());
        setBulkAction("");
        setBulkImageUrl("");
        if (viewMode === "flagged") fetchProducts();
        else searchProducts();
      } else {
        alert(data.error || "Bulk action failed");
      }
    } catch (err) {
      alert("Failed to execute bulk action");
    } finally {
      setBulkLoading(false);
    }
  };

  // Single product toggle
  const handleToggle = async (sku: string, field: "hidden" | "flagged", currentValue: boolean) => {
    try {
      await fetch("/api/admin/products", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productType,
          sku,
          hidden: field === "hidden" ? !currentValue : undefined,
          flagged: field === "flagged" ? !currentValue : undefined,
        }),
      });
      if (viewMode === "flagged") fetchProducts();
      else searchProducts();
    } catch (err) {
      alert("Failed to update");
    }
  };

  // Save image for single product
  const handleSaveImage = async (sku: string) => {
    try {
      await fetch("/api/admin/products", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productType,
          sku,
          imageUrl: imageUrl || null,
        }),
      });
      setEditingImage(null);
      setImageUrl("");
      if (viewMode === "flagged") fetchProducts();
      else searchProducts();
    } catch (err) {
      alert("Failed to save image URL");
    }
  };

  const currentItems = viewMode === "flagged" ? products : searchResults;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Product Controls</h1>
          <p className="text-neutral-400 mt-1">
            Search, flag, hide, or fix images for products
          </p>
        </div>

        {/* View Mode Toggle */}
        <div className="flex rounded-lg overflow-hidden border border-neutral-600">
          <button
            onClick={() => setViewMode("flagged")}
            className={`px-4 py-2 text-sm font-medium ${
              viewMode === "flagged"
                ? "bg-red-600 text-white"
                : "bg-neutral-700 text-neutral-300 hover:bg-neutral-600"
            }`}
          >
            📋 Flagged
          </button>
          <button
            onClick={() => setViewMode("search")}
            className={`px-4 py-2 text-sm font-medium ${
              viewMode === "search"
                ? "bg-red-600 text-white"
                : "bg-neutral-700 text-neutral-300 hover:bg-neutral-600"
            }`}
          >
            🔍 Search Catalog
          </button>
        </div>
      </div>

      {/* Stats (flagged view only) */}
      {viewMode === "flagged" && counts && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <StatCard label="Flagged" value={parseInt(counts.flagged_count)} color="amber" />
          <StatCard label="Hidden" value={parseInt(counts.hidden_count)} color="red" />
          <StatCard label="Missing Images" value={parseInt(counts.missing_image_count || "0")} color="orange" />
          <StatCard label="Total Tracked" value={parseInt(counts.total_count)} color="neutral" />
        </div>
      )}

      {/* Filters */}
      <div className="bg-neutral-800 rounded-xl border border-neutral-700 p-4">
        <div className="flex flex-wrap items-center gap-4">
          {/* Product Type */}
          <div className="flex items-center gap-2">
            <span className="text-sm text-neutral-400">Type:</span>
            <select
              value={productType}
              onChange={(e) => setProductType(e.target.value as any)}
              className="h-9 rounded-lg bg-neutral-700 border border-neutral-600 px-3 text-white text-sm"
            >
              <option value="wheel">🛞 Wheels</option>
              <option value="tire">⚫ Tires</option>
            </select>
          </div>

          {viewMode === "flagged" && (
            /* Filter for flagged view */
            <div className="flex items-center gap-2">
              <span className="text-sm text-neutral-400">Filter:</span>
              <div className="flex rounded-lg overflow-hidden border border-neutral-600">
                {(["all", "flagged", "hidden", "missing_image"] as const).map((f) => (
                  <button
                    key={f}
                    onClick={() => setFilter(f)}
                    className={`px-3 py-1.5 text-sm font-medium whitespace-nowrap ${
                      filter === f
                        ? "bg-red-600 text-white"
                        : "bg-neutral-700 text-neutral-300 hover:bg-neutral-600"
                    }`}
                  >
                    {f === "missing_image" ? "No Image" : f.charAt(0).toUpperCase() + f.slice(1)}
                  </button>
                ))}
              </div>
            </div>
          )}

          {viewMode === "search" && (
            /* Search input and filters */
            <>
              <div className="flex-1 min-w-[250px]">
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Search by SKU, UPC, name, or brand..."
                  className="w-full h-9 rounded-lg bg-neutral-700 border border-neutral-600 px-3 text-white text-sm"
                  autoFocus
                />
              </div>

              {searchFilters.suppliers.length > 0 && (
                <select
                  value={selectedSupplier}
                  onChange={(e) => setSelectedSupplier(e.target.value)}
                  className="h-9 rounded-lg bg-neutral-700 border border-neutral-600 px-3 text-white text-sm"
                >
                  <option value="">All Suppliers</option>
                  {searchFilters.suppliers.map(s => (
                    <option key={s} value={s}>{s}</option>
                  ))}
                </select>
              )}

              {searchFilters.brands.length > 0 && (
                <select
                  value={selectedBrand}
                  onChange={(e) => setSelectedBrand(e.target.value)}
                  className="h-9 rounded-lg bg-neutral-700 border border-neutral-600 px-3 text-white text-sm max-w-[150px]"
                >
                  <option value="">All Brands</option>
                  {searchFilters.brands.slice(0, 50).map(b => (
                    <option key={b} value={b}>{b}</option>
                  ))}
                </select>
              )}
            </>
          )}
        </div>

        {/* Bulk Actions */}
        {selectedSkus.size > 0 && (
          <div className="mt-4 pt-4 border-t border-neutral-700 flex flex-wrap items-center gap-3">
            <span className="text-sm text-white font-medium">
              {selectedSkus.size} selected
            </span>
            <button onClick={clearSelection} className="text-xs text-neutral-400 hover:text-white">
              Clear
            </button>
            <div className="h-4 w-px bg-neutral-600" />

            <select
              value={bulkAction}
              onChange={(e) => setBulkAction(e.target.value)}
              className="h-8 rounded bg-neutral-700 border border-neutral-600 px-2 text-white text-sm"
            >
              <option value="">Bulk action...</option>
              <option value="hide">🚫 Hide from search</option>
              <option value="unhide">✅ Unhide</option>
              <option value="flag">🚩 Flag for review</option>
              <option value="unflag">✓ Unflag</option>
              <option value="setImage">🖼️ Set image URL</option>
            </select>

            {bulkAction === "setImage" && (
              <input
                type="text"
                value={bulkImageUrl}
                onChange={(e) => setBulkImageUrl(e.target.value)}
                placeholder="https://..."
                className="h-8 w-64 rounded bg-neutral-700 border border-neutral-600 px-2 text-white text-sm"
              />
            )}

            <button
              onClick={executeBulkAction}
              disabled={!bulkAction || bulkLoading || (bulkAction === "setImage" && !bulkImageUrl)}
              className="h-8 px-4 rounded bg-red-600 text-white text-sm font-medium hover:bg-red-700 disabled:opacity-50"
            >
              {bulkLoading ? "..." : "Apply"}
            </button>
          </div>
        )}
      </div>

      {/* Results Table */}
      <div className="bg-neutral-800 rounded-xl border border-neutral-700 overflow-hidden">
        {(viewMode === "flagged" && loading) || (viewMode === "search" && searchLoading) ? (
          <div className="p-8 text-center text-neutral-500">Loading...</div>
        ) : currentItems.length === 0 ? (
          <div className="p-8 text-center text-neutral-500">
            {viewMode === "search" 
              ? (searchQuery.length < 2 ? "Enter at least 2 characters to search" : "No products found")
              : "No flagged products yet"}
          </div>
        ) : (
          <>
            {/* Select All */}
            <div className="px-4 py-2 bg-neutral-700/50 border-b border-neutral-700 flex items-center gap-3">
              <button
                onClick={selectAll}
                className="text-xs text-blue-400 hover:text-blue-300"
              >
                Select all ({currentItems.length})
              </button>
              {selectedSkus.size > 0 && (
                <button onClick={clearSelection} className="text-xs text-neutral-400 hover:text-white">
                  Clear selection
                </button>
              )}
            </div>

            <table className="w-full">
              <thead>
                <tr className="border-b border-neutral-700 text-left text-sm text-neutral-400">
                  <th className="px-4 py-3 w-10"></th>
                  <th className="px-4 py-3 font-medium">Product</th>
                  <th className="px-4 py-3 font-medium">Image</th>
                  <th className="px-4 py-3 font-medium">Status</th>
                  {viewMode === "search" && <th className="px-4 py-3 font-medium">Details</th>}
                  <th className="px-4 py-3 font-medium"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-neutral-700">
                {viewMode === "flagged" 
                  ? products.map((p) => (
                      <FlaggedRow
                        key={p.id}
                        product={p}
                        selected={selectedSkus.has(p.sku)}
                        onToggleSelect={() => toggleSelection(p.sku)}
                        onToggle={handleToggle}
                        editingImage={editingImage}
                        imageUrl={imageUrl}
                        setEditingImage={setEditingImage}
                        setImageUrl={setImageUrl}
                        onSaveImage={handleSaveImage}
                      />
                    ))
                  : searchResults.map((p) => (
                      <SearchRow
                        key={p.sku}
                        product={p}
                        selected={selectedSkus.has(p.sku)}
                        onToggleSelect={() => toggleSelection(p.sku)}
                        onToggle={handleToggle}
                        editingImage={editingImage}
                        imageUrl={imageUrl}
                        setEditingImage={setEditingImage}
                        setImageUrl={setImageUrl}
                        onSaveImage={handleSaveImage}
                      />
                    ))
                }
              </tbody>
            </table>
          </>
        )}
      </div>
    </div>
  );
}

function FlaggedRow({
  product,
  selected,
  onToggleSelect,
  onToggle,
  editingImage,
  imageUrl,
  setEditingImage,
  setImageUrl,
  onSaveImage,
}: {
  product: ProductFlag;
  selected: boolean;
  onToggleSelect: () => void;
  onToggle: (sku: string, field: "hidden" | "flagged", current: boolean) => void;
  editingImage: string | null;
  imageUrl: string;
  setEditingImage: (id: string | null) => void;
  setImageUrl: (url: string) => void;
  onSaveImage: (sku: string) => void;
}) {
  return (
    <tr className={`hover:bg-neutral-700/50 ${selected ? "bg-neutral-700/30" : ""}`}>
      <td className="px-4 py-3">
        <input
          type="checkbox"
          checked={selected}
          onChange={onToggleSelect}
          className="rounded bg-neutral-600 border-neutral-500"
        />
      </td>
      <td className="px-4 py-3">
        <div className="flex items-center gap-2">
          <span className="text-lg">{product.product_type === "wheel" ? "🛞" : "⚫"}</span>
          <div>
            <code className="text-sm text-white bg-neutral-700 px-2 py-0.5 rounded">
              {product.sku}
            </code>
            {product.brand && (
              <div className="text-xs text-neutral-500 mt-0.5">{product.brand}</div>
            )}
          </div>
        </div>
      </td>
      <td className="px-4 py-3">
        <ImageCell
          sku={product.sku}
          imageUrl={product.image_url}
          editing={editingImage === product.id}
          editValue={imageUrl}
          onEdit={() => { setEditingImage(product.id); setImageUrl(product.image_url || ""); }}
          onCancel={() => { setEditingImage(null); setImageUrl(""); }}
          onChange={setImageUrl}
          onSave={() => onSaveImage(product.sku)}
        />
      </td>
      <td className="px-4 py-3">
        <div className="flex items-center gap-2">
          <StatusToggle
            label="Hidden"
            active={product.hidden}
            color="red"
            onClick={() => onToggle(product.sku, "hidden", product.hidden)}
          />
          <StatusToggle
            label="Flagged"
            active={product.flagged}
            color="amber"
            onClick={() => onToggle(product.sku, "flagged", product.flagged)}
          />
        </div>
      </td>
      <td className="px-4 py-3 text-xs text-neutral-500">
        {new Date(product.updated_at).toLocaleDateString()}
      </td>
    </tr>
  );
}

function SearchRow({
