import { NextResponse } from "next/server";
import { XMLParser } from "fast-xml-parser";

export const runtime = "nodejs";

function getKmApiKey() {
  return (
    process.env.KM_API_KEY ||
    process.env.KMTIRE_API_KEY ||
    process.env.KM_TIRE_API_KEY ||
    ""
  ).trim();
}

function toTireSizeCompact(size: string) {
  // Accept formats like:
  // - 245/50R18
  // - 245/40ZR20 95Y
  // - 2455018
  // - 37135022 (flotation rawSize: 37x13.50R22 -> 37135022)
  // - 37x13.50R22
  const s = String(size || "").trim().toUpperCase();

  // Flotation string -> rawSize digits
  // 37x13.50R22 -> 37135022
  const f = s.match(/^(\d{2})\s*[X]\s*(\d{1,2}\.\d{2})\s*R\s*(\d{2}(?:\.5)?)\s*(?:LT)?$/i);
  if (f) {
    const dia = f[1];
    const width = f[2].replace(".", "");
    const rim = f[3].replace(".", "");
    return `${dia}${width}${rim}`;
  }

  const m = s.match(/(\d{3})\s*\/?\s*(\d{2})\s*[A-Z]*\s*R\s*(\d{2})/i);
  if (m) return `${m[1]}${m[2]}${m[3]}`;

  const m2 = s.match(/^\d{7}$/);
  if (m2) return s;

  const m3 = s.match(/^\d{8}$/);
  if (m3) return s;

  return "";
}

export async function GET(req: Request) {
  const url = new URL(req.url);
  const apiKey = getKmApiKey();
  if (!apiKey) {
    return NextResponse.json(
      { error: "Missing KM_API_KEY (or KMTIRE_API_KEY)" },
      { status: 500 }
    );
  }

  const tireSizeRaw = url.searchParams.get("tireSize") || url.searchParams.get("size") || "";
  const tireSize = toTireSizeCompact(tireSizeRaw);
  const minQty = url.searchParams.get("minQty") || "";
  const debug = (url.searchParams.get("debug") || "").trim() === "1";

  if (!tireSize) {
    return NextResponse.json(
      { error: "tireSize_required", hint: "Example: 245/50R18 or 2455018" },
      { status: 400 }
    );
  }

  const xml = `<?xml version="1.0" encoding="UTF-8"?>\n` +
    `<InventoryRequest>` +
    `<Credentials><APIKey>${apiKey}</APIKey></Credentials>` +
    `<Item>` +
    `<TireSize>${tireSize}</TireSize>` +
    (minQty ? `<MinQty>${minQty}</MinQty>` : ``) +
    `</Item>` +
    `</InventoryRequest>`;

  const upstream = "https://api.kmtire.com/v1/tiresizesearch";
  const res = await fetch(upstream, {
    method: "POST",
    headers: {
      "content-type": "application/xml",
      accept: "application/xml, text/xml, */*",
    },
    body: xml,
    cache: "no-store",
  });

  const text = await res.text();
  if (!res.ok) {
    return NextResponse.json(
      { error: "km_upstream_error", status: res.status, body: text.slice(0, 2000) },
      { status: 502 }
    );
  }

  const parser = new XMLParser({
    ignoreAttributes: false,
    // K&M wraps some strings in CDATA
    cdataPropName: "__cdata",
  });

  let data: unknown;
  try {
    data = parser.parse(text) as unknown;
  } catch {
    return NextResponse.json(
      { error: "km_xml_parse_error", body: text.slice(0, 2000) },
      { status: 502 }
    );
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const d = data as any;
  const resp = d?.InventoryResponse || d?.inventoryresponse || d;
  const itemsRaw = resp?.Item;

  function pick(it: any, keys: string[]) {
    for (const k of keys) {
      const v = it?.[k];
      if (v == null) continue;
      const cdata = typeof v === "object" && v?.__cdata != null ? v.__cdata : null;
      return cdata != null ? cdata : v;
    }
    return undefined;
  }

  function toBool(v: unknown): boolean | undefined {
    if (v == null) return undefined;
    const s = String(v).trim().toLowerCase();
    if (["y", "yes", "true", "1"].includes(s)) return true;
    if (["n", "no", "false", "0"].includes(s)) return false;
    return undefined;
  }

  const items = (Array.isArray(itemsRaw) ? itemsRaw : itemsRaw ? [itemsRaw] : []).map((it) => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const anyIt = it as any;
    const qty = anyIt?.Quantity || {};
    const brand = pick(anyIt, ["BrandName", "VendorName", "Brand", "Vendor"]);
    const desc = pick(anyIt, ["Description", "Desc"]);

    const season = pick(anyIt, ["Season", "TireType", "Category"]);
    const speedRating = pick(anyIt, ["SpeedRating", "Speed_Rating", "Speed"]);
    const loadRange = pick(anyIt, ["LoadRange", "Load_Range", "LoadRangeCode"]);
    const runFlat = toBool(pick(anyIt, ["RunFlat", "Runflat", "IsRunFlat", "RunFlatIndicator"]));
    const snowRated = toBool(pick(anyIt, ["SnowRated", "Snow_Rated", "ThreePeak", "3PMSF", "Is3PMSF"]));
    const allWeather = toBool(pick(anyIt, ["AllWeather", "All_Weather", "IsAllWeather"]));

    const utqgTreadwear = pick(anyIt, ["UTQGTreadwear", "UTQG_Treadwear", "Treadwear"]);
    const utqgTraction = pick(anyIt, ["UTQGTraction", "UTQG_Traction", "Traction"]);
    const utqgTemperature = pick(anyIt, ["UTQGTemperature", "UTQG_Temperature", "Temperature"]);

    const mileageWarranty = pick(anyIt, ["MileageWarranty", "Mileage_Warranty", "WarrantyMiles"]);
    const rebate = toBool(pick(anyIt, ["Rebate", "RebateAvailable", "HasRebate"]));
    const special = toBool(pick(anyIt, ["Special", "OnSpecial", "Promo"]));

    return {
      partNumber: anyIt?.PartNumber,
      mfgPartNumber: anyIt?.MfgPartNumber,
      brand: brand != null ? String(brand).trim() : undefined,
      description: desc != null ? String(desc).trim() : undefined,
      size: anyIt?.Size,
      cost: anyIt?.Cost != null ? Number(anyIt.Cost) : undefined,
      fet: anyIt?.FET != null ? Number(anyIt.FET) : undefined,
      quantity: {
        primary: qty?.Primary != null ? Number(qty.Primary) : undefined,
        alternate: qty?.Alternate != null ? Number(qty.Alternate) : undefined,
        national: qty?.National != null ? Number(qty.National) : undefined,
      },
      code: anyIt?.Code != null ? String(anyIt.Code) : undefined,

      // Extended merchandising/fitment fields (best-effort; keys depend on K&M schema)
      season: season != null ? String(season).trim() : undefined,
      speedRating: speedRating != null ? String(speedRating).trim() : undefined,
      loadRange: loadRange != null ? String(loadRange).trim() : undefined,
      runFlat,
      snowRated,
      allWeather,
      utqg: {
        treadwear: utqgTreadwear != null ? String(utqgTreadwear).trim() : undefined,
        traction: utqgTraction != null ? String(utqgTraction).trim() : undefined,
        temperature: utqgTemperature != null ? String(utqgTemperature).trim() : undefined,
      },
      mileageWarranty: mileageWarranty != null ? String(mileageWarranty).trim() : undefined,
      rebateAvailable: rebate,
      special,

      ...(debug
        ? {
            _debugKeys: Object.keys(anyIt || {}).slice(0, 200),
          }
        : null),
    };
  });

  return NextResponse.json({
    tireSize,
    resultCode: resp?.ResultCode != null ? String(resp.ResultCode) : undefined,
    resultMessage: resp?.ResultMessage != null ? String(resp.ResultMessage) : undefined,
    items,
    ...(debug
      ? {
          debug: {
            itemCount: items.length,
            firstItemKeys: items[0] && (items[0] as any)._debugKeys ? (items[0] as any)._debugKeys : [],
          },
        }
      : null),
  });
}

/**
 * Unified Tire Search API
 * 
 * Accepts vehicle params (year, make, model, modification) + optional wheelDiameter
 * Returns tires that fit the vehicle.
 * 
 * Sources:
 * - WheelPros local database (wp_tires)
 * - Tirewire (ATD, NTW, US AutoForce) via SOAP API
 * 
 * Flow:
 * 1. If size param provided → direct size search
 * 2. If vehicle params provided:
 *    a. Get tire sizes for vehicle from tire-sizes API
 *    b. Filter to wheelDiameter if provided
 *    c. Search tires matching those sizes from all sources
 */

import { NextResponse } from "next/server";
import pg from "pg";
import { searchTiresTirewire, tirewireTireToUnified, type UnifiedTire } from "@/lib/tirewire/client";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

const { Pool } = pg;

function required(name: string) {
  const v = process.env[name];
  if (!v) throw new Error(`Missing env var: ${name}`);
  return v;
}

let pool: pg.Pool | null = null;
function getPool() {
  if (pool) return pool;
  const DATABASE_URL = required("DATABASE_URL");
  pool = new Pool({
    connectionString: DATABASE_URL,
    ssl: { rejectUnauthorized: false },
    max: 5,
  });
  return pool;
}

function n(v: any): number | null {
  const x = Number(v);
  return Number.isFinite(x) ? x : null;
}

function i(v: any): number {
  const x = Number(v);
  return Number.isFinite(x) ? Math.trunc(x) : 0;
}

function toSimpleSize(s: string): string {
  // Accept formats like:
  // - 245/50R18 → 2455018
  // - 245/40ZR20 95Y → 2454020
  // - 2455018 → 2455018
  const v = String(s || "").trim().toUpperCase();
  const m = v.match(/(\d{3})\s*\/\s*(\d{2})\s*[A-Z]*\s*R?\s*(\d{2})/i);
  if (m) return `${m[1]}${m[2]}${m[3]}`;
  const m2 = v.match(/^(\d{7})$/);
  if (m2) return m2[1];
  return "";
}

function extractRimDiameter(size: string): number | null {
  // Extract rim diameter from tire size
  // 245/50R18 → 18
  // 2455018 → 18
  const simple = toSimpleSize(size);
  if (simple && simple.length === 7) {
    return parseInt(simple.slice(5), 10);
  }
  const m = size.match(/R(\d{2})/i);
  if (m) return parseInt(m[1], 10);
  return null;
}

interface TireResult {
  partNumber: string;
  mfgPartNumber: string;
  brand: string | null;
  model?: string | null;
  description: string;
  cost: number | null;
  price?: number | null;
  quantity: { primary: number; alternate: number; national: number };
  imageUrl: string | null;
  size: string;
  simpleSize: string;
  rimDiameter: number | null;
  tireLibraryId?: number | null;
  source?: string; // "wheelpros", "tirewire:atd", "tirewire:ntw", etc.
  badges: {
    terrain: string | null;
    construction: string | null;
    warrantyMiles: number | null;
    loadIndex: string | null;
    speedRating: string | null;
    utqg?: string | null;
  };
}

async function searchTiresBySize(
  db: pg.Pool,
  size: string,
  minQty: number,
  limit: number
): Promise<TireResult[]> {
  const simple = toSimpleSize(size) || size;

  const { rows } = await db.query({
    text: `
      select
        t.sku,
        t.brand_desc,
        t.tire_description,
        t.tire_size,
        t.simple_size,
        t.terrain,
        t.construction_type,
        t.mileage_warranty,
        t.load_index,
        t.speed_rating,
        t.image_url,
        t.map_usd,
        t.msrp_usd,
        coalesce(i.qoh, 0) as qoh
      from wp_tires t
      left join wp_inventory i
        on i.sku = t.sku
       and i.product_type = 'tire'
       and i.location_id = 'TOTAL'
      where (t.simple_size = $1 or t.tire_size ilike $2)
        and ($3::int is null or coalesce(i.qoh, 0) >= $3::int)
      order by coalesce(i.qoh, 0) desc, t.brand_desc asc, t.sku asc
      limit $4
    `,
    values: [simple, `%${simple}%`, minQty || null, limit],
  });

  return rows.map((r) => {
    const mapUsd0 = n(r.map_usd);
    const msrpUsd0 = n(r.msrp_usd);
    const mapUsd = mapUsd0 != null && mapUsd0 > 0.01 ? mapUsd0 : null;
    const msrpUsd = msrpUsd0 != null && msrpUsd0 > 0.01 ? msrpUsd0 : null;
    const cost = mapUsd != null ? Math.max(0.01, mapUsd - 50) : msrpUsd;
    const tireSize = r.tire_size || r.simple_size || "";

    return {
      partNumber: String(r.sku),
      mfgPartNumber: String(r.sku),
      brand: r.brand_desc || null,
      description: r.tire_description || tireSize || r.sku,
      cost: cost != null && Number.isFinite(cost) ? cost : null,
      quantity: { primary: 0, alternate: 0, national: i(r.qoh) },
      imageUrl: r.image_url || null,
      size: tireSize,
      simpleSize: r.simple_size || toSimpleSize(tireSize),
      rimDiameter: extractRimDiameter(tireSize),
      source: "wheelpros",
      badges: {
        terrain: r.terrain || null,
        construction: r.construction_type || null,
        warrantyMiles: r.mileage_warranty != null ? i(r.mileage_warranty) : null,
        loadIndex: r.load_index || null,
        speedRating: r.speed_rating || null,
      },
    };
  });
}

/**
 * Search Tirewire suppliers and convert to TireResult format
 */
async function searchTiresTirewireFormatted(size: string): Promise<TireResult[]> {
  try {
    const results = await searchTiresTirewire(size);
    const tires: TireResult[] = [];

    for (const result of results) {
      for (const tire of result.tires) {
        const unified = tirewireTireToUnified(tire, result.provider);
        tires.push({
          partNumber: unified.partNumber,
          mfgPartNumber: unified.mfgPartNumber,
          brand: unified.brand,
          model: unified.model,
          description: unified.description,
          cost: unified.cost,
          price: unified.price,
          quantity: unified.quantity,
          imageUrl: unified.imageUrl,
          size: unified.size,
          simpleSize: unified.simpleSize,
          rimDiameter: unified.rimDiameter,
          tireLibraryId: unified.tireLibraryId,
          source: unified.source,
          badges: {
            terrain: unified.badges.terrain,
            construction: unified.badges.construction,
            warrantyMiles: unified.badges.warrantyMiles,
            loadIndex: unified.badges.loadIndex,
            speedRating: unified.badges.speedRating,
            utqg: unified.badges.utqg,
          },
        });
      }
    }

    return tires;
  } catch (err) {
    console.error("[tires/search] Tirewire error:", err);
    return [];
  }
}

/**
 * Merge results from WheelPros and Tirewire, deduplicating by product code.
 * Tirewire results are preferred when duplicates exist (better images).
 */
function mergeTireResults(
  wpResults: TireResult[],
  twResults: TireResult[],
  minQty: number
): TireResult[] {
  const merged = new Map<string, TireResult>();

  // Add Tirewire results first (they have TireLibrary images)
  for (const tire of twResults) {
    const key = normalizeProductKey(tire.mfgPartNumber, tire.brand);
    const totalQty = tire.quantity.primary + tire.quantity.alternate + tire.quantity.national;
    if (minQty > 0 && totalQty < minQty) continue;
    merged.set(key, tire);
  }

  // Add WheelPros results if not already present
  for (const tire of wpResults) {
    const key = normalizeProductKey(tire.mfgPartNumber, tire.brand);
    if (!merged.has(key)) {
      merged.set(key, tire);
    } else {
      // Tire exists from Tirewire - aggregate quantity if different source
      const existing = merged.get(key)!;
      if (existing.source !== tire.source) {
        // Add WheelPros quantity to existing
        existing.quantity.national += tire.quantity.national;
      }
    }
  }

  // Sort by total quantity descending, then by brand
  return Array.from(merged.values()).sort((a, b) => {
    const qtyA = a.quantity.primary + a.quantity.alternate + a.quantity.national;
    const qtyB = b.quantity.primary + b.quantity.alternate + b.quantity.national;
    if (qtyB !== qtyA) return qtyB - qtyA;
    return (a.brand || "").localeCompare(b.brand || "");
  });
}

function normalizeProductKey(partNumber: string, brand: string | null): string {
  // Normalize part numbers for comparison
  // Remove common prefixes/suffixes and normalize case
  const normalized = String(partNumber || "")
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, "");
  return `${(brand || "").toUpperCase()}:${normalized}`;
}

export async function GET(req: Request) {
  const t0 = Date.now();
  const timing: Record<string, number> = {};

  try {
    const url = new URL(req.url);

    // Direct size search
    const sizeRaw = (url.searchParams.get("size") || url.searchParams.get("tireSize") || "").trim();

    // Vehicle params
    const year = url.searchParams.get("year");
    const make = url.searchParams.get("make");
    const model = url.searchParams.get("model");
    const modification = url.searchParams.get("modification") || url.searchParams.get("trim");
    const wheelDiameter = i(url.searchParams.get("wheelDiameter"));

    // Pagination
    const minQty = i(url.searchParams.get("minQty"));
    const pageSize = Math.min(Math.max(i(url.searchParams.get("pageSize") || url.searchParams.get("limit")) || 50, 1), 200);

    const tDb0 = Date.now();
    const db = getPool();
    timing.dbPoolMs = Date.now() - tDb0;

    // Case 1: Direct size search
    if (sizeRaw) {
      const tSearch0 = Date.now();
      // Query both sources in parallel
      const [wpResults, twResults] = await Promise.all([
        searchTiresBySize(db, sizeRaw, minQty, pageSize),
        searchTiresTirewireFormatted(sizeRaw),
      ]);
      timing.searchMs = Date.now() - tSearch0;

      // Merge and dedupe by partNumber (prefer Tirewire for images)
      const tMerge0 = Date.now();
      const merged = mergeTireResults(wpResults, twResults, minQty);
      const results = merged.slice(0, pageSize);
      timing.mergeMs = Date.now() - tMerge0;
      timing.totalMs = Date.now() - t0;

      return NextResponse.json({
        results,
        mode: "size",
        size: sizeRaw,
        sources: {
          wheelpros: wpResults.length,
          tirewire: twResults.length,
        },
        timing,
      });
    }

    // Case 2: Vehicle-based search
    if (!year || !make || !model) {
      return NextResponse.json({
        results: [],
        error: "Vehicle params (year, make, model) or size required",
      });
    }

    // Get tire sizes from vehicles/tire-sizes API
    const tFitment0 = Date.now();
    let tireSizes: string[] = [];
    let fitmentSource = "api";

    try {
      const tireSizesUrl = new URL(`${url.origin}/api/vehicles/tire-sizes`);
      tireSizesUrl.searchParams.set("year", year);
      tireSizesUrl.searchParams.set("make", make);
      tireSizesUrl.searchParams.set("model", model);
      if (modification) tireSizesUrl.searchParams.set("modification", modification);

      const tsRes = await fetch(tireSizesUrl.toString());
      if (tsRes.ok) {
        const tsData = await tsRes.json();
        tireSizes = (tsData.tireSizes || tsData.sizes || tsData.results || []).map((s: any) => 
          typeof s === "string" ? s : s.size || s.front || ""
        ).filter(Boolean);
      }
    } catch (err) {
      console.error("[tires/search] Tire sizes error:", err);
    }
    timing.fitmentMs = Date.now() - tFitment0;

    // Track original OEM sizes for response
    const oemTireSizes = [...tireSizes];

    // Filter by wheel diameter if specified
    let matchMode: "exact" | "oem-fallback" | "direct-search" = "exact";

    if (wheelDiameter && tireSizes.length > 0) {
      const filtered = tireSizes.filter((size) => {
        const rim = extractRimDiameter(size);
        return rim === wheelDiameter;
      });

      if (filtered.length > 0) {
        tireSizes = filtered;
        matchMode = "exact";
      } else {
        // No OEM tires match the wheel diameter - this is a plus/minus sizing scenario
        // Search directly for tires of the specified diameter
        tireSizes = [];
        matchMode = "direct-search";
        console.log(`[tires/search] No OEM tires for ${wheelDiameter}" wheel, using direct search`);
      }
    }

    // Build results from both sources
    const tSearch0 = Date.now();
    let wpResults: TireResult[] = [];
    let twResults: TireResult[] = [];

    if (tireSizes.length > 0) {
      // Search using OEM tire sizes (filtered by wheel diameter)
      const searchPromises: Promise<void>[] = [];

      for (const size of tireSizes.slice(0, 5)) {
        // WheelPros
        searchPromises.push(
          searchTiresBySize(db, size, minQty, Math.ceil(pageSize / tireSizes.length))
            .then((results) => { wpResults.push(...results); })
        );
        // Tirewire
        searchPromises.push(
          searchTiresTirewireFormatted(size)
            .then((results) => { twResults.push(...results); })
        );
      }

      await Promise.all(searchPromises);
    } else if (wheelDiameter && matchMode === "direct-search") {
      // Direct search by rim diameter when no OEM sizes match
      // Search for common sizes with this rim diameter
      const commonSizes = [`205/55R${wheelDiameter}`, `225/45R${wheelDiameter}`, `245/40R${wheelDiameter}`];

      const searchPromises: Promise<void>[] = [];
      for (const size of commonSizes) {
        searchPromises.push(
          searchTiresBySize(db, size, minQty, Math.ceil(pageSize / 3))
            .then((results) => { wpResults.push(...results.filter(t => t.rimDiameter === wheelDiameter)); })
        );
        searchPromises.push(
          searchTiresTirewireFormatted(size)
            .then((results) => { twResults.push(...results.filter(t => t.rimDiameter === wheelDiameter)); })
        );
      }
      await Promise.all(searchPromises);
    }
    timing.searchMs = Date.now() - tSearch0;

    // Merge results from both sources
    const allResults = mergeTireResults(wpResults, twResults, minQty);

    if (allResults.length === 0 && !wheelDiameter) {
      return NextResponse.json({
        results: [],
        mode: "vehicle",
        vehicle: { year, make, model, modification },
        wheelDiameter: wheelDiameter || null,
        error: "No tire sizes found for vehicle",
      });
    }

    // Final strict filter: only return tires matching wheelDiameter
    const filteredResults = wheelDiameter
      ? allResults.filter((t) => t.rimDiameter === wheelDiameter)
      : allResults;

    const finalResults = filteredResults.slice(0, pageSize);

    // If strict filtering leaves us empty but we have results, return error
    if (wheelDiameter && finalResults.length === 0 && allResults.length > 0) {
      return NextResponse.json({
        results: [],
        mode: "vehicle",
        vehicle: { year, make, model, modification },
        wheelDiameter,
        oemTireSizes,
        error: `No tires found for ${wheelDiameter}" wheels. OEM sizes are ${oemTireSizes.join(", ")}`,
        matchMode,
      });
    }

    timing.totalMs = Date.now() - t0;

    return NextResponse.json({
      results: finalResults,
      mode: "vehicle",
      vehicle: { year, make, model, modification },
      wheelDiameter: wheelDiameter || null,
      tireSizesSearched: tireSizes.length > 0 ? tireSizes : [`direct:R${wheelDiameter}`],
      oemTireSizes,
      matchMode,
      fitmentSource,
      sources: {
        wheelpros: wpResults.length,
        tirewire: twResults.length,
      },
      timing,
    });
  } catch (e: any) {
    console.error("[tires/search] Error:", e);
    return NextResponse.json(
      { results: [], error: e?.message || String(e) },
      { status: 200 }
    );
  }
}

/**
 * Tirewire Connections Center API Client
 * 
 * Queries tire inventory from multiple suppliers (ATD, NTW, US AutoForce)
 * via the Tirewire SOAP API. Returns TireLibrary-enriched data including
 * images, specs, and pricing.
 */

import crypto from "crypto";
import pg from "pg";

const { Pool } = pg;

// ============ Types ============

export interface TirewireCredentials {
  accessKey: string;
  groupToken: string;
}

export interface TirewireConnection {
  provider: string;
  connectionId: number;
  enabled: boolean;
}

export interface TirewireTire {
  id: number; // TireLibrary ID
  productCode: string;
  clientProductCode: string;
  name: string;
  make: string;
  makeId: number;
  pattern: string;
  patternId: number;
  description: string;
  imageUrl: string | null;
  width: number;
  aspectRatio: number;
  rim: number;
  weight: number | null;
  speedRating: string | null;
  loadRating: string | null;
  plyRating: string | null;
  utqg: string | null;
  loadRange: string | null;
  sidewall: string | null;
  treadDepth: string | null;
  warranty: string | null;
  features: string | null;
  benefits: string | null;
  buyPrice: number;
  sellPrice: number | null;
  tax: number;
  quantity: number;
  quantitySecondary: number;
  connectionId: number;
  supplierSystemId: number;
}

export interface TirewireSearchResult {
  tires: TirewireTire[];
  unmappedCount: number;
  message: string | null;
  connectionId: number;
  provider: string;
}

// ============ Encryption ============

function getEncryptionKey(): Buffer {
  const key = process.env.CREDENTIALS_KEY || process.env.ADMIN_PASSWORD || "default-key-change-me";
  return crypto.scryptSync(key, "tireweb-salt", 32);
}

function decrypt(encrypted: string): string {
  try {
    const [ivHex, data] = encrypted.split(":");
    if (!ivHex || !data) return encrypted; // Not encrypted
    const iv = Buffer.from(ivHex, "hex");
    const decipher = crypto.createDecipheriv("aes-256-cbc", getEncryptionKey(), iv);
    let decrypted = decipher.update(data, "hex", "utf8");
    decrypted += decipher.final("utf8");
    return decrypted;
  } catch {
    return encrypted; // Return as-is if decryption fails
  }
}

// ============ Database ============

// OPTIMIZATION: Reuse pool instead of creating/destroying per call
let _tirewirePool: pg.Pool | null = null;
function getPool(): pg.Pool {
  if (_tirewirePool) return _tirewirePool;
  const url = process.env.DATABASE_URL || process.env.POSTGRES_URL;
  if (!url) throw new Error("Missing DATABASE_URL");
  _tirewirePool = new Pool({
    connectionString: url,
    ssl: { rejectUnauthorized: false },
    max: 3,
  });
  return _tirewirePool;
}

// OPTIMIZATION: Cache credentials and connections for 5 minutes
let _credsCache: { data: TirewireCredentials | null; expiresAt: number } | null = null;
let _connsCache: { data: TirewireConnection[]; expiresAt: number } | null = null;
const CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes

export async function getTirewireCredentials(): Promise<TirewireCredentials | null> {
  // Return from cache if valid
  if (_credsCache && _credsCache.expiresAt > Date.now()) {
    return _credsCache.data;
  }

  const pool = getPool();
  try {
    const { rows } = await pool.query(`
      SELECT key, value FROM tireweb_config WHERE key IN ('access_key', 'group_token')
    `);

    const accessKeyRow = rows.find((r: any) => r.key === "access_key");
    const groupTokenRow = rows.find((r: any) => r.key === "group_token");

    if (!accessKeyRow?.value || !groupTokenRow?.value) {
      _credsCache = { data: null, expiresAt: Date.now() + CACHE_TTL_MS };
      return null;
    }

    const result = {
      accessKey: decrypt(accessKeyRow.value),
      groupToken: decrypt(groupTokenRow.value),
    };
    _credsCache = { data: result, expiresAt: Date.now() + CACHE_TTL_MS };
    return result;
  } catch (err) {
    console.error("[tirewire] Failed to get credentials:", err);
    return null;
  }
  // NOTE: No longer ending pool - it's reused
}

export async function getEnabledConnections(): Promise<TirewireConnection[]> {
  // Return from cache if valid
  if (_connsCache && _connsCache.expiresAt > Date.now()) {
    return _connsCache.data;
  }

  const pool = getPool();
  try {
    const { rows } = await pool.query(`
      SELECT provider, connection_id, enabled 
      FROM tireweb_connections 
      WHERE enabled = true AND connection_id IS NOT NULL
    `);

    const result = rows.map((r: any) => ({
      provider: r.provider,
      connectionId: r.connection_id,
      enabled: r.enabled,
    }));
    _connsCache = { data: result, expiresAt: Date.now() + CACHE_TTL_MS };
    return result;
  } catch (err) {
    console.error("[tirewire] Failed to get connections:", err);
    return [];
  }
  // NOTE: No longer ending pool - it's reused
}

// ============ SOAP API ============

const PRODUCTS_SERVICE_URL = "http://ws.tirewire.com/connectionscenter/productsservice.asmx";

function buildGetTiresRequest(
  accessKey: string,
  groupToken: string,
  connectionId: number,
  tireSize: string, // e.g., "2256016"
  detailLevel: number = 10 // 0=min, 6=standard, 10=all
): string {
  return `<?xml version="1.0" encoding="utf-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/" xmlns:prod="http://ws.tirewire.com/connectionscenter/productsservice">
  <soap:Body>
    <prod:GetTires>
      <prod:options>
        <prod:AccessKey>${escapeXml(accessKey)}</prod:AccessKey>
        <prod:GroupToken>${escapeXml(groupToken)}</prod:GroupToken>
        <prod:ConnectionID>${connectionId}</prod:ConnectionID>
        <prod:TireSize>${escapeXml(tireSize)}</prod:TireSize>
        <prod:DetailLevel>${detailLevel}</prod:DetailLevel>
      </prod:options>
    </prod:GetTires>
  </soap:Body>
</soap:Envelope>`;
}

function escapeXml(str: string): string {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

async function callTirewireApi(soapBody: string): Promise<string> {
  const res = await fetch(PRODUCTS_SERVICE_URL, {
    method: "POST",
    headers: {
      "Content-Type": "text/xml;charset=UTF-8",
      "SOAPAction": "http://ws.tirewire.com/connectionscenter/productsservice/GetTires",
    },
    body: soapBody,
  });

  if (!res.ok) {
    throw new Error(`Tirewire API error: ${res.status} ${res.statusText}`);
  }

  return res.text();
}

function parseGetTiresResponse(xml: string, connectionId: number, provider: string): TirewireSearchResult {
  const tires: TirewireTire[] = [];

  // Extract Tire elements
  const tireMatches = xml.matchAll(/<Tire>([\s\S]*?)<\/Tire>/g);

  for (const match of tireMatches) {
    const tireXml = match[1];

    const tire: TirewireTire = {
      id: extractInt(tireXml, "ID") || 0,
      productCode: extractString(tireXml, "ProductCode") || "",
      clientProductCode: extractString(tireXml, "ClientProductCode") || "",
      name: extractString(tireXml, "Name") || "",
      make: extractString(tireXml, "Make") || "",
      makeId: extractInt(tireXml, "MakeID") || 0,
      pattern: extractString(tireXml, "Pattern") || "",
      patternId: extractInt(tireXml, "PatternID") || 0,
      description: extractString(tireXml, "Description") || "",
      imageUrl: extractString(tireXml, "ImageURL") || null,
      width: extractFloat(tireXml, "Width") || 0,
      aspectRatio: extractFloat(tireXml, "AspectRatio") || 0,
      rim: extractFloat(tireXml, "Rim") || 0,
      weight: extractFloat(tireXml, "Weight"),
      speedRating: extractString(tireXml, "SpeedRating"),
      loadRating: extractString(tireXml, "LoadRating"),
      plyRating: extractString(tireXml, "PlyRating"),
      utqg: extractString(tireXml, "UTQG"),
      loadRange: extractString(tireXml, "LoadRange"),
      sidewall: extractString(tireXml, "Sidewall"),
      treadDepth: extractString(tireXml, "TreadDepth"),
      warranty: extractString(tireXml, "Warranty"),
      features: extractString(tireXml, "Features"),
      benefits: extractString(tireXml, "Benefits"),
      buyPrice: extractFloat(tireXml, "BuyPrice") || 0,
      sellPrice: extractFloat(tireXml, "SellPrice"),
      tax: extractFloat(tireXml, "Tax") || 0,
      quantity: extractInt(tireXml, "Quantity") || 0,
      quantitySecondary: extractInt(tireXml, "QuantitySecondary") || 0,
      connectionId,
      supplierSystemId: extractInt(tireXml, "SupplierSystemID") || 0,
    };

    tires.push(tire);
  }

  const unmappedCount = extractInt(xml, "UnmappedCount") || 0;
  const message = extractString(xml, "Message");

  return { tires, unmappedCount, message, connectionId, provider };
}

function extractString(xml: string, tag: string): string | null {
  const match = xml.match(new RegExp(`<${tag}>([\\s\\S]*?)<\\/${tag}>`));
  if (!match) return null;
  const value = match[1].trim();
  return value || null;
}

function extractInt(xml: string, tag: string): number | null {
  const str = extractString(xml, tag);
  if (!str) return null;
  const num = parseInt(str, 10);
  return isNaN(num) ? null : num;
}

function extractFloat(xml: string, tag: string): number | null {
  const str = extractString(xml, tag);
  if (!str) return null;
  const num = parseFloat(str);
  return isNaN(num) ? null : num;
}

// ============ Main Search Function ============

export async function searchTiresTirewire(
  tireSize: string // e.g., "225/60R16" or "2256016"
): Promise<TirewireSearchResult[]> {
  // Normalize size to simple format (2256016)
  const simpleSize = toSimpleSize(tireSize);
  if (!simpleSize) {
    console.warn("[tirewire] Invalid tire size:", tireSize);
    return [];
  }

  // Get credentials
  const creds = await getTirewireCredentials();
  if (!creds) {
    console.warn("[tirewire] No credentials configured");
    return [];
  }

  // Get enabled connections
  const connections = await getEnabledConnections();
  if (connections.length === 0) {
    console.warn("[tirewire] No enabled connections");
    return [];
  }

  // Query each connection in parallel
  const results = await Promise.allSettled(
    connections.map(async (conn) => {
      const soapRequest = buildGetTiresRequest(
        creds.accessKey,
        creds.groupToken,
        conn.connectionId,
        simpleSize
      );

      const response = await callTirewireApi(soapRequest);
      return parseGetTiresResponse(response, conn.connectionId, conn.provider);
    })
  );

  // Collect successful results
  const successfulResults: TirewireSearchResult[] = [];

  for (let i = 0; i < results.length; i++) {
    const result = results[i];
    if (result.status === "fulfilled") {
      successfulResults.push(result.value);
    } else {
      console.error(`[tirewire] Connection ${connections[i].provider} failed:`, result.reason);
    }
  }

  return successfulResults;
}

function toSimpleSize(s: string): string {
  const v = String(s || "").trim().toUpperCase();
  const m = v.match(/(\d{3})\s*\/\s*(\d{2})\s*[A-Z]*\s*R?\s*(\d{2})/i);
  if (m) return `${m[1]}${m[2]}${m[3]}`;
  const m2 = v.match(/^(\d{7})$/);
  if (m2) return m2[1];
  return "";
}

// ============ Utility: Convert to unified format ============

export interface UnifiedTire {
  partNumber: string;
  mfgPartNumber: string;
  brand: string | null;
  model: string | null;
  description: string;
  cost: number | null;
  price: number | null;
  quantity: { primary: number; alternate: number; national: number };
  imageUrl: string | null;
  size: string;
  simpleSize: string;
  rimDiameter: number | null;
  tireLibraryId: number | null;
  source: string; // "tirewire:atd", "tirewire:ntw", "km", etc.
  badges: {
    terrain: string | null;
    construction: string | null;
    warrantyMiles: number | null;
    loadIndex: string | null;
    speedRating: string | null;
    utqg: string | null;
  };
}

export function tirewireTireToUnified(tire: TirewireTire, provider: string): UnifiedTire {
  const size = `${Math.round(tire.width)}/${Math.round(tire.aspectRatio)}R${Math.round(tire.rim)}`;

  return {
    partNumber: tire.clientProductCode || tire.productCode,
    mfgPartNumber: tire.productCode,
    brand: tire.make || null,
    model: tire.pattern || null,
    description: tire.name || tire.description || `${tire.make} ${tire.pattern}`.trim(),
    cost: tire.buyPrice > 0 ? tire.buyPrice : null,
    price: tire.sellPrice && tire.sellPrice > 0 ? tire.sellPrice : null,
    quantity: {
      primary: tire.quantity,
      alternate: tire.quantitySecondary,
      national: tire.quantity + tire.quantitySecondary,
    },
    imageUrl: tire.imageUrl || null,
    size,
    simpleSize: `${Math.round(tire.width)}${Math.round(tire.aspectRatio)}${Math.round(tire.rim)}`,
    rimDiameter: Math.round(tire.rim),
    tireLibraryId: tire.id || null,
    source: `tirewire:${provider.replace("tireweb_", "")}`,
    badges: {
      terrain: null, // Tirewire doesn't have terrain classification
      construction: null,
      warrantyMiles: tire.warranty ? parseInt(tire.warranty) || null : null,
      loadIndex: tire.loadRating || null,
      speedRating: tire.speedRating || null,
      utqg: tire.utqg || null,
    },
  };
}

