    // Take top 8, ensuring brand variety
    const picks: Tire[] = [];
    const usedBrands = new Map<string, number>();
    
    for (const { tire } of scored) {
      if (picks.length >= 8) break;
      const brand = String(tire.brand || "").toLowerCase();
      const brandCount = usedBrands.get(brand) || 0;
      
