function pickKmField(it: any, keys: string[]): string | null {
  for (const k of keys) {
    const v = it?.[k];
    if (v == null) continue;
    const cdata = typeof v === "object" && v?.__cdata != null ? v.__cdata : null;
    return cdata != null ? String(cdata) : String(v);
  }
  return null;
}

